/* eslint-disable @typescript-eslint/no-explicit-any */
'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useRouter } from 'next/navigation';
import { reviewService, productService } from '@/services/api';
import Link from 'next/link';
import { FiArrowLeft, FiStar, FiTrash2 } from 'react-icons/fi';
import styles from './avaliacoes.module.scss';

export default function AdminAvaliacoesPage() {
  const { user, loading: authLoading } = useAuth();
  const router = useRouter();
  const [avaliacoes, setAvaliacoes] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [produtos, setProdutos] = useState<any[]>([]);

  useEffect(() => {
    if (!authLoading && (!user || !user.is_admin)) {
      router.push('/perfil');
    }
  }, [user, authLoading, router]);

  useEffect(() => {
    if (user && user.is_admin) {
      carregarDados();
    }
  }, [user]);

  const carregarDados = async () => {
    setLoading(true);
    try {
      // Carregar produtos para depois buscar avaliações
      const produtosRes = await productService.getAllAdmin({ limite: 100 });
      if (produtosRes.success) {
        const prods = produtosRes.data || [];
        setProdutos(prods);

        // Carregar avaliações de cada produto
        const todasAvaliacoes: any[] = [];
        for (const prod of prods.slice(0, 20)) {
          // Limitar a 20 produtos por performance
          try {
            const avalRes = await reviewService.getByProduct(prod.id, { limite: 50 });
            if (avalRes.success && avalRes.data) {
              const avalWithProduto = avalRes.data.map((av: any) => ({
                ...av,
                produto_nome: prod.nome,
                produto_id: prod.id,
              }));
              todasAvaliacoes.push(...avalWithProduto);
            }
          } catch (error) {
            console.error(`Erro ao carregar avaliações do produto ${prod.id}:`, error);
          }
        }
        setAvaliacoes(todasAvaliacoes);
      }
    } catch (error) {
      console.error('Erro ao carregar dados:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id: number) => {
    if (!confirm('Tem certeza que deseja excluir esta avaliação?')) {
      return;
    }

    try {
      const response = await reviewService.delete(id);
      if (response.success) {
        alert('Avaliação excluída com sucesso!');
        carregarDados();
      }
    } catch (error: any) {
      alert(error.message || 'Erro ao excluir avaliação');
    }
  };

  const renderStars = (nota: number) => {
    return (
      <div className={styles.stars}>
        {[1, 2, 3, 4, 5].map((star) => (
          <FiStar
            key={star}
            size={16}
            fill={star <= nota ? '#ffc107' : 'none'}
            color="#ffc107"
          />
        ))}
      </div>
    );
  };

  const mediaNotas = avaliacoes.length
    ? (avaliacoes.reduce((acc, av) => acc + av.nota, 0) / avaliacoes.length).toFixed(1)
    : 0;

  if (authLoading || loading) {
    return (
      <div className={styles.loading}>
        <div className="spinner-border" role="status"></div>
      </div>
    );
  }

  if (!user || !user.is_admin) {
    return null;
  }

  return (
    <div className={styles.adminAvaliacoes}>
      <div className={styles.container}>
        <div className={styles.header}>
          <div className={styles.headerLeft}>
            <Link href="/admin" className={styles.backButton}>
              <FiArrowLeft /> Voltar
            </Link>
            <h1>Gerenciar Avaliações</h1>
          </div>
        </div>

        <div className={styles.stats}>
          <div className={styles.statCard}>
            <FiStar size={24} />
            <div>
              <p>Total de Avaliações</p>
              <h3>{avaliacoes.length}</h3>
            </div>
          </div>
          <div className={styles.statCard}>
            <FiStar size={24} />
            <div>
              <p>Média Geral</p>
              <h3>{mediaNotas} ⭐</h3>
            </div>
          </div>
        </div>

        <div className={styles.tableContainer}>
          <table className={styles.table}>
            <thead>
              <tr>
                <th>Produto</th>
                <th>Usuário</th>
                <th>Nota</th>
                <th>Data</th>
                <th>Verificado</th>
                <th>Ações</th>
              </tr>
            </thead>
            <tbody>
              {avaliacoes.map((avaliacao) => (
                <tr key={avaliacao.id}>
                  <td>
                    <Link href={`/produtos/${avaliacao.produto_id}`}>
                      {avaliacao.produto_nome}
                    </Link>
                  </td>
                  <td>{avaliacao.usuario_nome || 'Anônimo'}</td>
                  <td>{renderStars(avaliacao.nota)}</td>
                  <td>{new Date(avaliacao.data_avaliacao).toLocaleDateString('pt-BR')}</td>
                  <td>
                    {avaliacao.verificado_compra ? (
                      <span className={styles.badgeSuccess}>Sim</span>
                    ) : (
                      <span className={styles.badgeSecondary}>Não</span>
                    )}
                  </td>
                  <td>
                    <div className={styles.actions}>
                      <button
                        onClick={() => handleDelete(avaliacao.id)}
                        className={styles.btnDelete}
                        title="Excluir"
                      >
                        <FiTrash2 /> Excluir
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          {avaliacoes.length === 0 && (
            <div className={styles.empty}>
              <p>Nenhuma avaliação encontrada</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

/* eslint-disable @typescript-eslint/no-explicit-any */
'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useToast } from '@/contexts/ToastContext';
import { useRouter } from 'next/navigation';
import { badgeService, productService } from '@/services/api';
import Link from 'next/link';
import { FiArrowLeft, FiPlus, FiEdit, FiTrash2, FiTag, FiStar, FiX } from 'react-icons/fi';
import styles from './badges.module.scss';

interface Badge {
  id: number;
  nome: string;
  tipo: 'best_seller' | 'mais_vendido' | 'novo' | 'limitado';
  cor?: string;
  icone?: string;
  ativo: boolean;
  data_criacao: string;
}

interface Produto {
  id: number;
  nome: string;
  preco: number;
  imagem_url?: string;
}

export default function AdminBadgesPage() {
  const { user, loading: authLoading } = useAuth();
  const { showToast } = useToast();
  const router = useRouter();

  const [badges, setBadges] = useState<Badge[]>([]);
  const [produtos, setProdutos] = useState<Produto[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [showProdutosModal, setShowProdutosModal] = useState(false);
  const [editingBadge, setEditingBadge] = useState<Badge | null>(null);
  const [selectedBadge, setSelectedBadge] = useState<Badge | null>(null);
  const [selectedProdutoId, setSelectedProdutoId] = useState<number>(0);

  const [formData, setFormData] = useState({
    nome: '',
    tipo: 'novo' as 'best_seller' | 'mais_vendido' | 'novo' | 'limitado',
    cor: '#FF6B6B',
    icone: '⭐',
    ativo: true,
  });

  const tiposBadge = [
    { value: 'best_seller', label: 'Best Seller', icon: '🏆' },
    { value: 'mais_vendido', label: 'Mais Vendido', icon: '🔥' },
    { value: 'novo', label: 'Novo', icon: '✨' },
    { value: 'limitado', label: 'Edição Limitada', icon: '💎' },
  ];

  const coresPreDefinidas = [
    '#FF6B6B', // Vermelho
    '#4ECDC4', // Turquesa
    '#45B7D1', // Azul
    '#FFA07A', // Laranja
    '#98D8C8', // Verde claro
    '#FFD93D', // Amarelo
    '#6C5CE7', // Roxo
    '#FF6348', // Vermelho coral
  ];

  useEffect(() => {
    if (!authLoading && (!user || !user.is_admin)) {
      router.push('/perfil');
    }
  }, [user, authLoading, router]);

  useEffect(() => {
    if (user && user.is_admin) {
      carregarBadges();
      carregarProdutos();
    }
  }, [user]);

  const carregarBadges = async () => {
    setLoading(true);
    try {
      const response = await badgeService.getAll();
      if (response.success) {
        setBadges(response.data || []);
      }
    } catch (error) {
      console.error('Erro ao carregar badges:', error);
      showToast('Erro ao carregar badges', 'error');
    } finally {
      setLoading(false);
    }
  };

  const carregarProdutos = async () => {
    try {
      const response = await productService.getAllAdmin({ limite: 1000 });
      if (response.success) {
        setProdutos(response.data || []);
      }
    } catch (error) {
      console.error('Erro ao carregar produtos:', error);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.nome.trim()) {
      showToast('Nome do badge é obrigatório', 'error');
      return;
    }

    try {
      if (editingBadge) {
        const response = await badgeService.update(editingBadge.id, formData);
        if (response.success) {
          showToast('Badge atualizado com sucesso!', 'success');
        }
      } else {
        const response = await badgeService.create(formData);
        if (response.success) {
          showToast('Badge criado com sucesso!', 'success');
        }
      }

      setShowModal(false);
      resetForm();
      carregarBadges();
    } catch (error: any) {
      showToast(error.message || 'Erro ao salvar badge', 'error');
    }
  };

  const handleEdit = (badge: Badge) => {
    setEditingBadge(badge);
    setFormData({
      nome: badge.nome,
      tipo: badge.tipo,
      cor: badge.cor || '#FF6B6B',
      icone: badge.icone || '⭐',
      ativo: badge.ativo,
    });
    setShowModal(true);
  };

  const handleDelete = async (id: number) => {
    if (!confirm('Tem certeza que deseja excluir este badge?')) {
      return;
    }

    try {
      const response = await badgeService.delete(id);
      if (response.success) {
        showToast('Badge excluído com sucesso!', 'success');
        carregarBadges();
      }
    } catch (error: any) {
      showToast(error.message || 'Erro ao excluir badge', 'error');
    }
  };

  const handleAdicionarProduto = (badge: Badge) => {
    setSelectedBadge(badge);
    setShowProdutosModal(true);
  };

  const handleVincularProduto = async () => {
    if (!selectedBadge || !selectedProdutoId) {
      showToast('Selecione um produto', 'error');
      return;
    }

    try {
      const response = await badgeService.addToProduct(selectedProdutoId, selectedBadge.id);
      if (response.success) {
        showToast('Badge vinculado ao produto com sucesso!', 'success');
        setShowProdutosModal(false);
        setSelectedProdutoId(0);
      }
    } catch (error: any) {
      showToast(error.message || 'Erro ao vincular badge', 'error');
    }
  };

  const resetForm = () => {
    setFormData({
      nome: '',
      tipo: 'novo',
      cor: '#FF6B6B',
      icone: '⭐',
      ativo: true,
    });
    setEditingBadge(null);
  };

  const handleOpenModal = () => {
    resetForm();
    setShowModal(true);
  };

  if (authLoading || !user || !user.is_admin) {
    return null;
  }

  return (
    <div className={styles.adminBadgesPage}>
      <div className="container">
        {/* Header */}
        <div className={styles.header}>
          <div>
            <Link href="/admin" className={styles.backButton}>
              <FiArrowLeft /> Voltar
            </Link>
            <h1><FiTag /> Gerenciar Badges</h1>
            <p>Crie e gerencie badges para destacar produtos especiais</p>
          </div>
          <button className={styles.addButton} onClick={handleOpenModal}>
            <FiPlus /> Novo Badge
          </button>
        </div>

        {/* Lista de Badges */}
        {loading ? (
          <div className={styles.loading}>Carregando badges...</div>
        ) : badges.length === 0 ? (
          <div className={styles.empty}>
            <FiTag size={48} />
            <h2>Nenhum badge cadastrado</h2>
            <p>Comece criando seu primeiro badge</p>
            <button onClick={handleOpenModal}>
              <FiPlus /> Criar Primeiro Badge
            </button>
          </div>
        ) : (
          <div className={styles.badgeGrid}>
            {badges.map((badge) => (
              <div key={badge.id} className={styles.badgeCard}>
                <div className={styles.badgeHeader}>
                  <div className={styles.badgePreview} style={{ backgroundColor: badge.cor }}>
                    <span className={styles.badgeIcon}>{badge.icone}</span>
                    <span className={styles.badgeNome}>{badge.nome}</span>
                  </div>
                  <span className={`${styles.status} ${badge.ativo ? styles.ativo : styles.inativo}`}>
                    {badge.ativo ? 'Ativo' : 'Inativo'}
                  </span>
                </div>

                <div className={styles.badgeInfo}>
                  <div className={styles.infoRow}>
                    <span className={styles.label}>Tipo:</span>
                    <span className={styles.value}>
                      {tiposBadge.find(t => t.value === badge.tipo)?.label || badge.tipo}
                    </span>
                  </div>
                  <div className={styles.infoRow}>
                    <span className={styles.label}>Criado em:</span>
                    <span className={styles.value}>
                      {new Date(badge.data_criacao).toLocaleDateString('pt-BR')}
                    </span>
                  </div>
                </div>

                <div className={styles.badgeActions}>
                  <button
                    className={styles.vinculoButton}
                    onClick={() => handleAdicionarProduto(badge)}
                    title="Vincular a produto"
                  >
                    <FiStar /> Vincular
                  </button>
                  <button
                    className={styles.editButton}
                    onClick={() => handleEdit(badge)}
                    title="Editar"
                  >
                    <FiEdit />
                  </button>
                  <button
                    className={styles.deleteButton}
                    onClick={() => handleDelete(badge.id)}
                    title="Excluir"
                  >
                    <FiTrash2 />
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Modal de Criar/Editar Badge */}
        {showModal && (
          <div className={styles.modal}>
            <div className={styles.modalContent}>
              <div className={styles.modalHeader}>
                <h2>{editingBadge ? 'Editar Badge' : 'Novo Badge'}</h2>
                <button onClick={() => setShowModal(false)}>
                  <FiX />
                </button>
              </div>

              <form onSubmit={handleSubmit}>
                <div className={styles.formGroup}>
                  <label>Nome do Badge *</label>
                  <input
                    type="text"
                    value={formData.nome}
                    onChange={(e) => setFormData({ ...formData, nome: e.target.value })}
                    placeholder="Ex: Super Oferta"
                    required
                  />
                </div>

                <div className={styles.formGroup}>
                  <label>Tipo *</label>
                  <div className={styles.tipoGrid}>
                    {tiposBadge.map((tipo) => (
                      <label key={tipo.value} className={styles.tipoOption}>
                        <input
                          type="radio"
                          name="tipo"
                          value={tipo.value}
                          checked={formData.tipo === tipo.value}
                          onChange={(e) => setFormData({ ...formData, tipo: e.target.value as any })}
                        />
                        <div className={styles.tipoCard}>
                          <span className={styles.tipoIcon}>{tipo.icon}</span>
                          <span className={styles.tipoLabel}>{tipo.label}</span>
                        </div>
                      </label>
                    ))}
                  </div>
                </div>

                <div className={styles.formGroup}>
                  <label>Cor do Badge</label>
                  <div className={styles.coresGrid}>
                    {coresPreDefinidas.map((cor) => (
                      <button
                        key={cor}
                        type="button"
                        className={`${styles.corOption} ${formData.cor === cor ? styles.selected : ''}`}
                        style={{ backgroundColor: cor }}
                        onClick={() => setFormData({ ...formData, cor })}
                      />
                    ))}
                  </div>
                  <input
                    type="color"
                    value={formData.cor}
                    onChange={(e) => setFormData({ ...formData, cor: e.target.value })}
                    className={styles.colorPicker}
                  />
                </div>

                <div className={styles.formGroup}>
                  <label>Ícone (Emoji)</label>
                  <input
                    type="text"
                    value={formData.icone}
                    onChange={(e) => setFormData({ ...formData, icone: e.target.value })}
                    placeholder="⭐"
                    maxLength={2}
                  />
                  <small>Use emojis: ⭐ 🔥 ✨ 💎 🏆 ⚡ 🎉 🎁</small>
                </div>

                <div className={styles.formGroup}>
                  <label className={styles.checkboxLabel}>
                    <input
                      type="checkbox"
                      checked={formData.ativo}
                      onChange={(e) => setFormData({ ...formData, ativo: e.target.checked })}
                    />
                    Badge ativo
                  </label>
                </div>

                {/* Preview */}
                <div className={styles.preview}>
                  <label>Preview:</label>
                  <div className={styles.badgePreviewLarge} style={{ backgroundColor: formData.cor }}>
                    <span className={styles.previewIcon}>{formData.icone}</span>
                    <span className={styles.previewNome}>{formData.nome || 'Nome do Badge'}</span>
                  </div>
                </div>

                <div className={styles.modalActions}>
                  <button type="button" onClick={() => setShowModal(false)} className={styles.cancelButton}>
                    Cancelar
                  </button>
                  <button type="submit" className={styles.submitButton}>
                    {editingBadge ? 'Atualizar' : 'Criar'} Badge
                  </button>
                </div>
              </form>
            </div>
          </div>
        )}

        {/* Modal de Vincular Produto */}
        {showProdutosModal && selectedBadge && (
          <div className={styles.modal}>
            <div className={styles.modalContent}>
              <div className={styles.modalHeader}>
                <h2>Vincular Badge: {selectedBadge.nome}</h2>
                <button onClick={() => setShowProdutosModal(false)}>
                  <FiX />
                </button>
              </div>

              <div className={styles.produtosList}>
                <label>Selecione um produto:</label>
                <select
                  value={selectedProdutoId}
                  onChange={(e) => setSelectedProdutoId(Number(e.target.value))}
                  className={styles.produtoSelect}
                >
                  <option value={0}>Escolha um produto...</option>
                  {produtos.map((produto) => (
                    <option key={produto.id} value={produto.id}>
                      {produto.nome} - R$ {Number(produto.preco).toFixed(2)}
                    </option>
                  ))}
                </select>
              </div>

              <div className={styles.modalActions}>
                <button type="button" onClick={() => setShowProdutosModal(false)} className={styles.cancelButton}>
                  Cancelar
                </button>
                <button 
                  type="button" 
                  onClick={handleVincularProduto} 
                  className={styles.submitButton}
                  disabled={!selectedProdutoId}
                >
                  Vincular Badge
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

/* eslint-disable @typescript-eslint/no-explicit-any */
'use client';

import { useAuth } from '@/contexts/AuthContext';
import { useRouter } from 'next/navigation';
import { useEffect, useState } from 'react';
import Link from 'next/link';
import { ArrowLeft, Plus, Edit2, Trash2, Eye, EyeOff, GripVertical, Save } from 'lucide-react';
import { bannerService } from '@/services/api';
import { useNotification } from '@/hooks/useNotification';
import { confirmDelete, showSuccess, showError } from '@/utils/alerts';
import styles from './banners.module.scss';

const API_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000/api';

interface Banner {
  id: number;
  titulo: string;
  subtitulo?: string;
  texto_botao?: string;
  link_botao?: string;
  imagem?: string;
  cor_fundo: string;
  ordem: number;
  ativo: boolean;
  data_inicio?: string;
  data_fim?: string;
  data_criacao: string;
}

export default function BannersPage() {
  const { user, loading: authLoading } = useAuth();
  const router = useRouter();
  const [banners, setBanners] = useState<Banner[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editingBanner, setEditingBanner] = useState<Banner | null>(null);
  const [uploading, setUploading] = useState(false);
  const [imagemTipo, setImagemTipo] = useState<'url' | 'upload'>('url');
  const [formData, setFormData] = useState({
    titulo: '',
    subtitulo: '',
    texto_botao: '',
    link_botao: '',
    imagem: '',
    cor_fundo: '#0C1C3A',
    ordem: 0,
    ativo: true,
    data_inicio: '',
    data_fim: '',
  });

  useEffect(() => {
    if (!authLoading && (!user || !user.is_admin)) {
      router.push('/perfil');
    }
  }, [user, authLoading, router]);

  useEffect(() => {
    if (user && user.is_admin) {
      carregarBanners();
    }
  }, [user]);

  const carregarBanners = async () => {
    try {
      setLoading(true);
      const response = await bannerService.getAll(false);
      if (response.success && response.data) {
        setBanners(response.data);
      }
    } catch (error: any) {
      console.error('Erro ao carregar banners:', error);
      showError('Erro ao carregar banners: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  const abrirModal = (banner?: Banner) => {
    if (banner) {
      setEditingBanner(banner);
      setFormData({
        titulo: banner.titulo,
        subtitulo: banner.subtitulo || '',
        texto_botao: banner.texto_botao || '',
        link_botao: banner.link_botao || '',
        imagem: banner.imagem || '',
        cor_fundo: banner.cor_fundo || '#0C1C3A',
        ordem: banner.ordem,
        ativo: banner.ativo,
        data_inicio: banner.data_inicio ? banner.data_inicio.split('T')[0] : '',
        data_fim: banner.data_fim ? banner.data_fim.split('T')[0] : '',
      });
    } else {
      setEditingBanner(null);
      setFormData({
        titulo: '',
        subtitulo: '',
        texto_botao: 'Ver Mais',
        link_botao: '/produtos',
        imagem: '',
        cor_fundo: '#0C1C3A',
        ordem: banners.length,
        ativo: true,
        data_inicio: '',
        data_fim: '',
      });
    }
    setShowModal(true);
  };

  const fecharModal = () => {
    setShowModal(false);
    setEditingBanner(null);
    setImagemTipo('url');
  };

  const handleUploadImagem = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Validar tipo de arquivo
    const allowedTypes = ['image/jpeg', 'image/jpg', 'image/png', 'image/gif', 'image/webp'];
    if (!allowedTypes.includes(file.type)) {
      showError('Tipo de arquivo não suportado. Use apenas imagens (JPEG, PNG, GIF, WEBP).');
      return;
    }

    // Validar tamanho (5MB)
    if (file.size > 5 * 1024 * 1024) {
      showError('Arquivo muito grande. O tamanho máximo é 5MB.');
      return;
    }

    setUploading(true);
    try {
      const formDataUpload = new FormData();
      formDataUpload.append('imagem', file);

      const token = localStorage.getItem('token');
      const response = await fetch(`${API_URL}/produtos/upload-imagem`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
        },
        body: formDataUpload,
      });

      const data = await response.json();

      if (data.success && data.data.url) {
        // Usar a URL da imagem (verificar se precisa do host)
        const imageUrl = data.data.url.startsWith('http') 
          ? data.data.url 
          : `${API_URL.replace('/api', '')}${data.data.url}`;

        setFormData(prev => ({
          ...prev,
          imagem: imageUrl,
        }));
        showSuccess('Imagem enviada com sucesso!');
      } else {
        showError(data.message || 'Erro ao fazer upload da imagem');
      }
    } catch (error: any) {
      console.error('Erro ao fazer upload:', error);
      showError('Erro ao fazer upload da imagem: ' + error.message);
    } finally {
      setUploading(false);
      // Limpar o input file
      e.target.value = '';
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.titulo.trim()) {
      showError('O título é obrigatório');
      return;
    }

    try {
      const dataToSend: any = {
        titulo: formData.titulo,
        subtitulo: formData.subtitulo || undefined,
        texto_botao: formData.texto_botao || undefined,
        link_botao: formData.link_botao || undefined,
        imagem: formData.imagem || undefined,
        cor_fundo: formData.cor_fundo,
        ordem: formData.ordem,
        ativo: formData.ativo,
        data_inicio: formData.data_inicio || undefined,
        data_fim: formData.data_fim || undefined,
      };

      if (editingBanner) {
        await bannerService.update(editingBanner.id, dataToSend);
        showSuccess('Banner atualizado com sucesso!');
      } else {
        await bannerService.create(dataToSend);
        showSuccess('Banner criado com sucesso!');
      }

      fecharModal();
      carregarBanners();
    } catch (error: any) {
      console.error('Erro ao salvar banner:', error);
      showError('Erro ao salvar banner: ' + error.message);
    }
  };

  const handleDelete = async (id: number) => {
    const shouldDelete = await confirmDelete('Excluir Banner?', 'Esta ação não pode ser desfeita!');

    if (!shouldDelete) {
      return;
    }

    try {
      await bannerService.delete(id);
      showSuccess('Banner excluído com sucesso!');
      carregarBanners();
    } catch (error: any) {
      console.error('Erro ao excluir banner:', error);
      showError('Erro ao excluir banner: ' + error.message);
    }
  };

  const handleToggleStatus = async (id: number) => {
    try {
      await bannerService.toggle(id);
      carregarBanners();
    } catch (error: any) {
      console.error('Erro ao alternar status:', error);
      alert('Erro ao alternar status: ' + error.message);
    }
  };

  const moveUp = async (index: number) => {
    if (index === 0) return;

    const newBanners = [...banners];
    [newBanners[index], newBanners[index - 1]] = [newBanners[index - 1], newBanners[index]];

    const reorderedBanners = newBanners.map((b, i) => ({ id: b.id, ordem: i }));

    try {
      await bannerService.reorder(reorderedBanners);
      carregarBanners();
    } catch (error: any) {
      console.error('Erro ao reordenar:', error);
      alert('Erro ao reordenar: ' + error.message);
    }
  };

  const moveDown = async (index: number) => {
    if (index === banners.length - 1) return;

    const newBanners = [...banners];
    [newBanners[index], newBanners[index + 1]] = [newBanners[index + 1], newBanners[index]];

    const reorderedBanners = newBanners.map((b, i) => ({ id: b.id, ordem: i }));

    try {
      await bannerService.reorder(reorderedBanners);
      carregarBanners();
    } catch (error: any) {
      console.error('Erro ao reordenar:', error);
      showError('Erro ao reordenar: ' + error.message);
    }
  };

  if (authLoading || loading) {
    return (
      <div className={styles.loading}>
        <div className="spinner-border" role="status">
          <span className="visually-hidden">Carregando...</span>
        </div>
      </div>
    );
  }

  if (!user || !user.is_admin) {
    return null;
  }

  return (
    <div className={styles.bannersPage}>
      <div className={styles.container}>
        <div className={styles.header}>
          <div className={styles.headerTop}>
            <Link href="/admin" className={styles.backButton}>
              <ArrowLeft size={18} /> Voltar
            </Link>
            <h1>Gerenciar Banners</h1>
          </div>

          <div className={styles.headerActions}>
            <button className={styles.addButton} onClick={() => abrirModal()}>
              <Plus size={18} /> Novo Banner
            </button>
          </div>
        </div>

        <div className={styles.stats}>
          <div className={styles.statCard}>
            <span className={styles.statLabel}>Total de Banners</span>
            <span className={styles.statValue}>{banners.length}</span>
          </div>
          <div className={styles.statCard}>
            <span className={styles.statLabel}>Banners Ativos</span>
            <span className={styles.statValue}>
              {banners.filter(b => b.ativo).length}
            </span>
          </div>
        </div>

        {banners.length === 0 ? (
          <div className={styles.emptyState}>
            <p>Nenhum banner cadastrado</p>
            <button className={styles.addButton} onClick={() => abrirModal()}>
              <Plus /> Criar Primeiro Banner
            </button>
          </div>
        ) : (
          <div className={styles.bannersGrid}>
            {banners.map((banner, index) => (
              <div key={banner.id} className={styles.bannerCard}>
                <div className={styles.bannerPreview} style={{ backgroundColor: banner.cor_fundo }}>
                  {banner.imagem && (
                    <img src={banner.imagem} alt={banner.titulo} />
                  )}
                  <div className={styles.bannerOverlay}>
                    <h3>{banner.titulo}</h3>
                    {banner.subtitulo && <p>{banner.subtitulo}</p>}
                  </div>
                </div>

                <div className={styles.bannerInfo}>
                  <div className={styles.bannerStatus}>
                    <span className={`${styles.badge} ${banner.ativo ? styles.active : styles.inactive}`}>
                      {banner.ativo ? 'Ativo' : 'Inativo'}
                    </span>
                    <span className={styles.ordem}>Ordem: {banner.ordem}</span>
                  </div>

                  <div className={styles.bannerDetails}>
                    {banner.texto_botao && (
                      <p><strong>Botão:</strong> {banner.texto_botao}</p>
                    )}
                    {banner.link_botao && (
                      <p><strong>Link:</strong> {banner.link_botao}</p>
                    )}
                  </div>

                  <div className={styles.bannerActions}>
                    <button
                      onClick={() => handleToggleStatus(banner.id)}
                      className={styles.iconButton}
                      title={banner.ativo ? 'Desativar' : 'Ativar'}
                    >
                      {banner.ativo ? <EyeOff size={18} /> : <Eye size={18} />}
                    </button>

                    <div className={styles.moveButtons}>
                      <button
                        onClick={() => moveUp(index)}
                        disabled={index === 0}
                        className={styles.iconButton}
                        title="Mover para cima"
                      >
                        ↑
                      </button>
                      <button
                        onClick={() => moveDown(index)}
                        disabled={index === banners.length - 1}
                        className={styles.iconButton}
                        title="Mover para baixo"
                      >
                        ↓
                      </button>
                    </div>

                    <button
                      onClick={() => abrirModal(banner)}
                      className={styles.iconButton}
                      title="Editar"
                    >
                      <Edit2 size={18} />
                    </button>

                    <button
                      onClick={() => handleDelete(banner.id)}
                      className={`${styles.iconButton} ${styles.danger}`}
                      title="Excluir"
                    >
                      <Trash2 size={18} />
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Modal de Criação/Edição */}
      {showModal && (
        <div className={styles.modalOverlay} onClick={fecharModal}>
          <div className={styles.modal} onClick={(e) => e.stopPropagation()}>
            <div className={styles.modalHeader}>
              <h2>{editingBanner ? 'Editar Banner' : 'Novo Banner'}</h2>
              <button onClick={fecharModal} className={styles.closeButton}>×</button>
            </div>

            <form onSubmit={handleSubmit} className={styles.modalBody}>
              <div className={styles.formGroup}>
                <label>Título *</label>
                <input
                  type="text"
                  value={formData.titulo}
                  onChange={(e) => setFormData({ ...formData, titulo: e.target.value })}
                  required
                  placeholder="Ex: MEGA BAZAR"
                />
              </div>

              <div className={styles.formGroup}>
                <label>Subtítulo</label>
                <input
                  type="text"
                  value={formData.subtitulo}
                  onChange={(e) => setFormData({ ...formData, subtitulo: e.target.value })}
                  placeholder="Ex: Até 70% OFF em peças selecionadas"
                />
              </div>

              <div className={styles.formRow}>
                <div className={styles.formGroup}>
                  <label>Texto do Botão</label>
                  <input
                    type="text"
                    value={formData.texto_botao}
                    onChange={(e) => setFormData({ ...formData, texto_botao: e.target.value })}
                    placeholder="Ex: Ver Ofertas"
                  />
                </div>

                <div className={styles.formGroup}>
                  <label>Link do Botão</label>
                  <input
                    type="text"
                    value={formData.link_botao}
                    onChange={(e) => setFormData({ ...formData, link_botao: e.target.value })}
                    placeholder="Ex: /promocoes"
                  />
                </div>
              </div>

              <div className={styles.formGroup}>
                <label>Imagem do Banner</label>
                <div style={{ marginBottom: '0.5rem' }}>
                  <label style={{ marginRight: '1rem', cursor: 'pointer' }}>
                    <input
                      type="radio"
                      value="url"
                      checked={imagemTipo === 'url'}
                      onChange={(e) => setImagemTipo('url')}
                      style={{ marginRight: '0.5rem' }}
                    />
                    URL da Imagem
                  </label>
                  <label style={{ cursor: 'pointer' }}>
                    <input
                      type="radio"
                      value="upload"
                      checked={imagemTipo === 'upload'}
                      onChange={(e) => setImagemTipo('upload')}
                      style={{ marginRight: '0.5rem' }}
                    />
                    Upload de Arquivo
                  </label>
                </div>

                {imagemTipo === 'url' ? (
                  <input
                    type="text"
                    value={formData.imagem}
                    onChange={(e) => setFormData({ ...formData, imagem: e.target.value })}
                    placeholder="Ex: /images/banner1.jpg"
                  />
                ) : (
                  <div>
                    <input
                      type="file"
                      id="upload-banner-imagem"
                      accept="image/jpeg,image/jpg,image/png,image/gif,image/webp"
                      onChange={handleUploadImagem}
                      disabled={uploading}
                      style={{ display: 'block', marginBottom: '0.5rem' }}
                    />
                    <small>Formatos aceitos: JPEG, PNG, GIF, WEBP (máx. 5MB)</small>
                    {uploading && <p style={{ marginTop: '0.5rem', color: '#666' }}>Enviando...</p>}
                  </div>
                )}

                {formData.imagem && (
                  <div style={{ marginTop: '1rem' }}>
                    <small>Preview:</small>
                    <img 
                      src={formData.imagem} 
                      alt="Preview" 
                      style={{ maxWidth: '100%', maxHeight: '150px', marginTop: '0.5rem', borderRadius: '4px' }}
                    />
                  </div>
                )}
              </div>

              <div className={styles.formRow}>
                <div className={styles.formGroup}>
                  <label>Cor de Fundo</label>
                  <div className={styles.colorPicker}>
                    <input
                      type="color"
                      value={formData.cor_fundo}
                      onChange={(e) => setFormData({ ...formData, cor_fundo: e.target.value })}
                    />
                    <input
                      type="text"
                      value={formData.cor_fundo}
                      onChange={(e) => setFormData({ ...formData, cor_fundo: e.target.value })}
                      placeholder="#0C1C3A"
                    />
                  </div>
                </div>

                <div className={styles.formGroup}>
                  <label>Ordem</label>
                  <input
                    type="number"
                    value={formData.ordem}
                    onChange={(e) => setFormData({ ...formData, ordem: parseInt(e.target.value) })}
                    min="0"
                  />
                </div>
              </div>

              <div className={styles.formRow}>
                <div className={styles.formGroup}>
                  <label>Data Início (opcional)</label>
                  <input
                    type="date"
                    value={formData.data_inicio}
                    onChange={(e) => setFormData({ ...formData, data_inicio: e.target.value })}
                  />
                </div>

                <div className={styles.formGroup}>
                  <label>Data Fim (opcional)</label>
                  <input
                    type="date"
                    value={formData.data_fim}
                    onChange={(e) => setFormData({ ...formData, data_fim: e.target.value })}
                  />
                </div>
              </div>

              <div className={styles.formGroup}>
                <label className={styles.checkboxLabel}>
                  <input
                    type="checkbox"
                    checked={formData.ativo}
                    onChange={(e) => setFormData({ ...formData, ativo: e.target.checked })}
                  />
                  <span>Banner Ativo</span>
                </label>
              </div>

              {/* Preview */}
              <div className={styles.previewSection}>
                <h3>Preview</h3>
                <div className={styles.previewBanner} style={{ backgroundColor: formData.cor_fundo }}>
                  <div className={styles.previewContent}>
                    <h2>{formData.titulo || 'Título do Banner'}</h2>
                    <p>{formData.subtitulo || 'Subtítulo do banner'}</p>
                    {formData.texto_botao && (
                      <button className={styles.previewButton}>{formData.texto_botao}</button>
                    )}
                  </div>
                </div>
              </div>

              <div className={styles.modalFooter}>
                <button type="button" onClick={fecharModal} className={styles.cancelButton}>
                  Cancelar
                </button>
                <button type="submit" className={styles.saveButton}>
                  <Save size={18} /> {editingBanner ? 'Atualizar' : 'Criar'} Banner
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

/* eslint-disable @typescript-eslint/no-explicit-any */
'use client';

import { useAuth } from '@/contexts/AuthContext';
import { useRouter } from 'next/navigation';
import { useEffect, useState } from 'react';
import Link from 'next/link';
import { ArrowLeft, Plus, Edit2, Trash2, Package, AlertCircle } from 'lucide-react';
import { caixaService } from '@/services/api';
import { confirmDelete, showSuccess, showError } from '@/utils/alerts';
import styles from '../admin.module.scss';

interface Caixa {
  id: number;
  codigo: string;
  nome: string;
  tamanho: 'P' | 'M' | 'G';
  altura: number;
  largura: number;
  comprimento: number;
  peso_caixa: number;
  ativo: boolean;
  created_at: string;
  updated_at: string;
}

export default function CaixasCatalogoPage() {
  const { user, loading: authLoading } = useAuth();
  const router = useRouter();
  const [caixas, setCaixas] = useState<Caixa[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editingCaixa, setEditingCaixa] = useState<Caixa | null>(null);
  const [filtroTamanho, setFiltroTamanho] = useState<'P' | 'M' | 'G' | ''>('');
  const [filtroAtivo, setFiltroAtivo] = useState<'true' | 'false' | ''>('');
  const [formData, setFormData] = useState({
    codigo: '',
    nome: '',
    tamanho: 'P' as 'P' | 'M' | 'G',
    altura: '',
    largura: '',
    comprimento: '',
    peso_caixa: '',
  });

  useEffect(() => {
    if (!authLoading && (!user || !user.is_admin)) {
      router.push('/perfil');
    }
  }, [user, authLoading, router]);

  useEffect(() => {
    if (user && user.is_admin) {
      carregarCaixas();
    }
  }, [user, filtroTamanho, filtroAtivo]);

  const carregarCaixas = async () => {
    try {
      setLoading(true);
      const params: any = {};
      if (filtroTamanho) params.tamanho = filtroTamanho;
      if (filtroAtivo) params.ativo = filtroAtivo === 'true';

      const response = await caixaService.getAll(params);
      if (response.success && response.data) {
        setCaixas(response.data);
      }
    } catch (error: any) {
      console.error('Erro ao carregar caixas:', error);
      showError('Erro ao carregar caixas: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  const abrirModal = (caixa?: Caixa) => {
    if (caixa) {
      setEditingCaixa(caixa);
      setFormData({
        codigo: caixa.codigo,
        nome: caixa.nome,
        tamanho: caixa.tamanho,
        altura: caixa.altura.toString(),
        largura: caixa.largura.toString(),
        comprimento: caixa.comprimento.toString(),
        peso_caixa: caixa.peso_caixa.toString(),
      });
    } else {
      setEditingCaixa(null);
      setFormData({
        codigo: '',
        nome: '',
        tamanho: 'P',
        altura: '',
        largura: '',
        comprimento: '',
        peso_caixa: '',
      });
    }
    setShowModal(true);
  };

  const fecharModal = () => {
    setShowModal(false);
    setEditingCaixa(null);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    try {
      const data = {
        codigo: formData.codigo.trim().toUpperCase(),
        nome: formData.nome.trim(),
        tamanho: formData.tamanho,
        altura: parseFloat(formData.altura),
        largura: parseFloat(formData.largura),
        comprimento: parseFloat(formData.comprimento),
        peso_caixa: parseFloat(formData.peso_caixa),
      };

      // Validações
      if (!data.codigo || data.codigo.length < 2 || data.codigo.length > 10) {
        showError('Código deve ter entre 2 e 10 caracteres');
        return;
      }

      if (!/^[A-Z0-9]+$/.test(data.codigo)) {
        showError('Código deve conter apenas letras e números');
        return;
      }

      if (!data.nome || data.nome.length < 3) {
        showError('Nome deve ter pelo menos 3 caracteres');
        return;
      }

      if (data.altura <= 0 || data.altura > 200) {
        showError('Altura deve estar entre 0 e 200 cm');
        return;
      }

      if (data.largura <= 0 || data.largura > 200) {
        showError('Largura deve estar entre 0 e 200 cm');
        return;
      }

      if (data.comprimento <= 0 || data.comprimento > 200) {
        showError('Comprimento deve estar entre 0 e 200 cm');
        return;
      }

      if (data.peso_caixa < 0 || data.peso_caixa > 50) {
        showError('Peso da caixa deve estar entre 0 e 50 kg');
        return;
      }

      if (editingCaixa) {
        const { codigo, tamanho, ...updateData } = data;
        await caixaService.update(editingCaixa.id, updateData);
        showSuccess('Caixa atualizada com sucesso!');
      } else {
        await caixaService.create(data);
        showSuccess('Caixa criada com sucesso!');
      }

      fecharModal();
      carregarCaixas();
    } catch (error: any) {
      console.error('Erro ao salvar caixa:', error);
      showError(error.message || 'Erro ao salvar caixa');
    }
  };

  const handleDesativar = async (caixa: Caixa) => {
    try {
      // Verificar uso
      const usoResponse = await caixaService.checkUsage(caixa.id);

      if (usoResponse.data?.em_uso) {
        const tipos = usoResponse.data?.tipos_vinculados || [];
        const tiposNomes = tipos.map((t: any) => t.nome).join(', ');
        showError(
          `Não é possível desativar esta caixa. Ela está sendo usada por: ${tiposNomes || 'configurações ativas'}`
        );
        return;
      }

      const confirmed = await confirmDelete(
        `Tem certeza que deseja desativar a caixa "${caixa.nome}"?`,
        'Esta ação pode ser revertida depois.'
      );

      if (confirmed) {
        await caixaService.deactivate(caixa.id);
        showSuccess('Caixa desativada com sucesso!');
        carregarCaixas();
      }
    } catch (error: any) {
      console.error('Erro ao desativar caixa:', error);
      showError(error.message || 'Erro ao desativar caixa');
    }
  };

  const handleAtivar = async (caixa: Caixa) => {
    try {
      await caixaService.update(caixa.id, { ativo: true });
      showSuccess('Caixa ativada com sucesso!');
      carregarCaixas();
    } catch (error: any) {
      console.error('Erro ao ativar caixa:', error);
      showError(error.message || 'Erro ao ativar caixa');
    }
  };

  const getTamanhoLabel = (tamanho: string) => {
    switch (tamanho) {
      case 'P': return 'Pequena';
      case 'M': return 'Média';
      case 'G': return 'Grande';
      default: return tamanho;
    }
  };

  const formatPesoCaixa = (valor: number | string) => {
    const peso = Number(valor);
    return Number.isFinite(peso) ? peso.toFixed(3) : '0.000';
  };

  const getTamanhoBadgeClass = (tamanho: string) => {
    switch (tamanho) {
      case 'P': return styles.badgeP;
      case 'M': return styles.badgeM;
      case 'G': return styles.badgeG;
      default: return '';
    }
  };

  if (authLoading || loading) {
    return (
      <div className={styles.container}>
        <div className={styles.loading}>
          <Package className={styles.spinner} />
          <p>Carregando...</p>
        </div>
      </div>
    );
  }

  if (!user || !user.is_admin) {
    return null;
  }

  return (
    <div className={styles.container}>
      <div className={styles.header}>
        <div>
          <Link href="/admin" className={styles.backButton}>
            <ArrowLeft size={20} />
            Voltar para Admin
          </Link>
          <h1 className={styles.title}>
            <Package size={32} />
            Catálogo de Caixas
          </h1>
          <p className={styles.subtitle}>
            Gerencie as caixas padrão (P/M/G) usadas no cálculo de frete
          </p>
        </div>
        <button onClick={() => abrirModal()} className={styles.primaryButton}>
          <Plus size={20} />
          Nova Caixa
        </button>
      </div>

      {/* Filtros */}
      <div className={styles.filters}>
        <div className={styles.filterGroup}>
          <label>Tamanho:</label>
          <select
            value={filtroTamanho}
            onChange={(e) => setFiltroTamanho(e.target.value as any)}
            className={styles.select}
          >
            <option value="">Todos</option>
            <option value="P">Pequena</option>
            <option value="M">Média</option>
            <option value="G">Grande</option>
          </select>
        </div>
        <div className={styles.filterGroup}>
          <label>Status:</label>
          <select
            value={filtroAtivo}
            onChange={(e) => setFiltroAtivo(e.target.value as any)}
            className={styles.select}
          >
            <option value="">Todos</option>
            <option value="true">Ativo</option>
            <option value="false">Inativo</option>
          </select>
        </div>
      </div>

      {/* Tabela */}
      <div className={styles.tableContainer}>
        <table className={styles.table}>
          <thead>
            <tr>
              <th>Código</th>
              <th>Nome</th>
              <th>Tamanho</th>
              <th>Dimensões (A×L×C cm)</th>
              <th>Peso Caixa (kg)</th>
              <th>Volume (cm³)</th>
              <th>Status</th>
              <th>Ações</th>
