'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useRouter } from 'next/navigation';
import { couponService } from '@/services/api';
import Link from 'next/link';
import { ArrowLeft, Plus, Edit, Trash2, Tag, Percent, DollarSign } from 'lucide-react';
import { toast } from 'sonner';
import styles from './cupons.module.scss';

interface Cupom {
  id: number;
  codigo: string;
  descricao?: string;
  tipo_desconto: 'percentual' | 'fixo';
  valor_desconto: number;
  valor_minimo?: number;
  data_validade?: string;
  usos_maximos?: number;
  usos_atuais: number;
  ativo: boolean;
  data_criacao: string;
}

export default function AdminCuponsPage() {
  const { user, loading: authLoading } = useAuth();
  const router = useRouter();
  const [cupons, setCupons] = useState<Cupom[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editingCupom, setEditingCupom] = useState<Cupom | null>(null);
  const [filtroStatus, setFiltroStatus] = useState<'all' | 'active' | 'inactive'>('all');

  const [formData, setFormData] = useState({
    codigo: '',
    descricao: '',
    tipo_desconto: 'percentual' as 'percentual' | 'fixo',
    valor_desconto: 1,
    valor_minimo: 0,
    data_validade: '',
    usos_maximos: 0,
    ativo: true,
  });

  useEffect(() => {
    if (!authLoading && (!user || !user.is_admin)) {
      router.push('/perfil');
    }
  }, [user, authLoading, router]);

  useEffect(() => {
    if (user && user.is_admin) {
      carregarCupons();
    }
  }, [user, filtroStatus]);

  const carregarCupons = async () => {
    setLoading(true);
    try {
      const params =
        filtroStatus === 'all'
          ? undefined
          : { ativo: filtroStatus === 'active' };
      const response = await couponService.getAll(params);
      if (response.success) {
        setCupons(response.data || []);
      }
    } catch (error) {
      console.error('Erro ao carregar cupons:', error);
      toast.error('Erro ao carregar cupons');
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // Validações
    if (!formData.codigo.trim()) {
      toast.error('Código do cupom é obrigatório');
      return;
    }

    if (formData.valor_desconto === undefined || formData.valor_desconto === null || formData.valor_desconto <= 0) {
      toast.error('Valor de desconto deve ser maior que zero');
      return;
    }

    if (!['percentual', 'fixo'].includes(formData.tipo_desconto)) {
      toast.error('Tipo de desconto inválido');
      return;
    }

    try {
      const dataToSend = {
        codigo: formData.codigo.toUpperCase(),
        descricao: formData.descricao || undefined,
        tipo_desconto: formData.tipo_desconto,
        valor_desconto: parseFloat(formData.valor_desconto.toString()) || 0,
        valor_minimo: formData.valor_minimo ? parseFloat(formData.valor_minimo.toString()) : 0,
        data_validade: formData.data_validade || undefined,
        usos_maximos: formData.usos_maximos ? parseInt(formData.usos_maximos.toString()) : undefined,
        ativo: formData.ativo,
      };

      if (editingCupom) {
        const response = await couponService.update(editingCupom.id, dataToSend);
        if (response.success) {
          toast.success('✨ Cupom atualizado com sucesso!');
        }
      } else {
        const response = await couponService.create(dataToSend);
        if (response.success) {
          toast.success('✨ Cupom criado com sucesso!');
        }
      }

      setShowModal(false);
      resetForm();
      carregarCupons();
    } catch (error: any) {
      toast.error(error.message || 'Erro ao salvar cupom');
    }
  };

  const handleEdit = (cupom: Cupom) => {
    setEditingCupom(cupom);
    setFormData({
      codigo: cupom.codigo,
      descricao: cupom.descricao || '',
      tipo_desconto: cupom.tipo_desconto,
      valor_desconto: cupom.valor_desconto,
      valor_minimo: cupom.valor_minimo || 0,
      data_validade: cupom.data_validade ? cupom.data_validade.split('T')[0] : '',
      usos_maximos: cupom.usos_maximos || 0,
      ativo: cupom.ativo,
    });
    setShowModal(true);
  };

  const handleDelete = async (id: number) => {
    if (!confirm('Tem certeza que deseja excluir este cupom?')) {
      return;
    }

    try {
      const response = await couponService.delete(id);
      if (response.success) {
        toast.success('✨ Cupom excluído com sucesso!');
        carregarCupons();
      }
    } catch (error: any) {
      toast.error(error.message || 'Erro ao excluir cupom');
    }
  };

  const resetForm = () => {
    setEditingCupom(null);
    setFormData({
      codigo: '',
      descricao: '',
      tipo_desconto: 'percentual',
      valor_desconto: 1,
      valor_minimo: 0,
      data_validade: '',
      usos_maximos: 0,
      ativo: true,
    });
  };

  const formatarData = (data: string) => {
    return new Date(data).toLocaleDateString('pt-BR');
  };

  const formatarValor = (valor: number | string | null | undefined, tipo: string) => {
    const numero = typeof valor === 'number' ? valor : parseFloat(valor || '0');

    if (tipo === 'percentual') {
      return `${Number.isNaN(numero) ? 0 : numero}%`;
    }

    return `R$ ${Number.isNaN(numero) ? '0.00' : numero.toFixed(2)}`;
  };

  if (authLoading || loading) {
    return (
      <div className={styles.loading}>
        <div className="spinner-border" role="status"></div>
      </div>
    );
  }

  if (!user || !user.is_admin) {
    return null;
  }

  return (
    <div className={styles.adminCupons}>
      <div className={styles.container}>
        <div className={styles.header}>
          <div className={styles.headerLeft}>
            <Link href="/admin" className={styles.backButton}>
              <ArrowLeft size={20} /> Voltar
            </Link>
            <h1>Gerenciar Cupons</h1>
          </div>
          <button
            onClick={() => {
              resetForm();
              setShowModal(true);
            }}
            className={styles.addButton}
          >
            <Plus size={20} /> Novo Cupom
          </button>
        </div>

        <div className={styles.stats}>
          <div className={styles.statCard}>
            <Tag size={24} />
            <div>
              <p>Total de Cupons</p>
              <h3>{cupons.length}</h3>
            </div>
          </div>
          <div className={styles.statCard}>
            <Percent size={24} />
            <div>
              <p>Cupons Ativos</p>
              <h3>{cupons.filter((c) => c.ativo).length}</h3>
            </div>
          </div>
          <div className={styles.statCard}>
            <DollarSign size={24} />
            <div>
              <p>Total de Usos</p>
              <h3>{cupons.reduce((acc, c) => acc + (c.usos_atuais || 0), 0)}</h3>
            </div>
          </div>
        </div>

        <div className={styles.filterBar}>
          <label className={styles.filterLabel} htmlFor="filtroStatus">
            Mostrar
          </label>
          <select
            id="filtroStatus"
            className={styles.filterSelect}
            value={filtroStatus}
            onChange={(e) => setFiltroStatus(e.target.value as 'all' | 'active' | 'inactive')}
          >
            <option value="all">Todos</option>
            <option value="active">Ativos</option>
            <option value="inactive">Inativos</option>
          </select>
        </div>

        <div className={styles.tableContainer}>
          <table className={styles.table}>
            <thead>
              <tr>
                <th>Código</th>
                <th>Tipo</th>
                <th>Desconto</th>
                <th>Valor Mínimo</th>
                <th>Validade</th>
                <th>Usos</th>
                <th>Status</th>
                <th>Ações</th>
              </tr>
            </thead>
            <tbody>
              {cupons.map((cupom) => (
                <tr key={cupom.id}>
                  <td>
                    <strong>{cupom.codigo}</strong>
                    {cupom.descricao && (
                      <small className={styles.descricao}>{cupom.descricao}</small>
                    )}
                  </td>
                  <td>
                    <span className={styles.tipoBadge}>
                      {cupom.tipo_desconto === 'percentual' ? 'Percentual' : 'Fixo'}
                    </span>
                  </td>
                  <td>{formatarValor(cupom.valor_desconto, cupom.tipo_desconto)}</td>
                  <td>
                    {cupom.valor_minimo && cupom.valor_minimo > 0
                      ? `R$ ${Number(cupom.valor_minimo).toFixed(2)}`
                      : 'Sem mínimo'}
                  </td>
                  <td>
                    {cupom.data_validade
                      ? formatarData(cupom.data_validade)
                      : 'Sem validade'}
                  </td>
                  <td>
                    {cupom.usos_atuais}
                    {cupom.usos_maximos ? ` / ${cupom.usos_maximos}` : ' / Ilimitado'}
                  </td>
                  <td>
                    <span className={`${styles.badge} ${cupom.ativo ? styles.badgeSuccess : styles.badgeDanger}`}>
                      {cupom.ativo ? 'Ativo' : 'Inativo'}
                    </span>
                  </td>
                  <td>
                    <div className={styles.actions}>
                      <button
                        onClick={() => handleEdit(cupom)}
                        className={styles.btnEdit}
                        title="Editar"
                      >
                        <Edit size={18} />
                      </button>
                      <button
                        onClick={() => handleDelete(cupom.id)}
                        className={styles.btnDelete}
                        title="Excluir"
                      >
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          {cupons.length === 0 && (
            <div className={styles.empty}>
              <Tag size={48} />
              <p>Nenhum cupom cadastrado</p>
            </div>
          )}
        </div>
      </div>

      {/* Modal de Criar/Editar */}
      {showModal && (
        <div className={styles.modal}>
          <div className={styles.modalContent}>
            <div className={styles.modalHeader}>
              <h2>{editingCupom ? 'Editar Cupom' : 'Novo Cupom'}</h2>
              <button
                onClick={() => {
                  setShowModal(false);
                  resetForm();
                }}
                className={styles.closeButton}
              >
                ×
              </button>
            </div>

            <form onSubmit={handleSubmit} className={styles.form}>
              <div className={styles.formGroup}>
                <label>Código do Cupom *</label>
                <input
                  type="text"
                  name="codigo"
                  value={formData.codigo}
                  onChange={(e) => setFormData({ ...formData, codigo: e.target.value.toUpperCase() })}
                  required
                  placeholder="Ex: PROMO10"
                  maxLength={20}
                />
              </div>

              <div className={styles.formGroup}>
                <label>Descrição</label>
                <input
                  type="text"
                  value={formData.descricao}
                  onChange={(e) => setFormData({ ...formData, descricao: e.target.value })}
                  placeholder="Ex: Desconto de 10% para primeira compra"
                />
              </div>

              <div className={styles.formRow}>
                <div className={styles.formGroup}>
                  <label>Tipo de Desconto *</label>
                  <select
                    name="tipo"
                    value={formData.tipo_desconto}
                    onChange={(e) =>
                      setFormData({ ...formData, tipo_desconto: e.target.value as any })
                    }
                    required
                  >
                    <option value="percentual">Percentual (%)</option>
                    <option value="fixo">Valor Fixo (R$)</option>
                  </select>
                </div>

                <div className={styles.formGroup}>
                  <label>Valor do Desconto *</label>
                  <input
                    type="number"
                    name="desconto"
                    step="0.01"
                    min="0"
                    value={formData.valor_desconto}
                    onChange={(e) =>
                      setFormData({ ...formData, valor_desconto: parseFloat(e.target.value) })
                    }
                    required
                    placeholder={formData.tipo_desconto === 'percentual' ? '10' : '50.00'}
                  />
                </div>
              </div>

              <div className={styles.formRow}>
                <div className={styles.formGroup}>
                  <label>Valor Mínimo da Compra</label>
                  <input
                    type="number"
                    step="0.01"
                    min="0"
                    value={formData.valor_minimo}
                    onChange={(e) =>
                      setFormData({ ...formData, valor_minimo: parseFloat(e.target.value) || 0 })
                    }
                    placeholder="0.00"
                  />
                </div>

                <div className={styles.formGroup}>
                  <label>Data de Validade</label>
                  <input
                    type="date"
                    value={formData.data_validade}
                    onChange={(e) => setFormData({ ...formData, data_validade: e.target.value })}
                  />
                </div>
              </div>

              <div className={styles.formGroup}>
                <label>Número Máximo de Usos</label>
                <input
                  type="number"
                  min="0"
                  value={formData.usos_maximos}
                  onChange={(e) =>
                    setFormData({ ...formData, usos_maximos: parseInt(e.target.value) || 0 })
                  }
                  placeholder="0 = Ilimitado"
                />
              </div>

              <div className={styles.formGroup}>
                <label className={styles.checkboxLabel}>
                  <input
                    type="checkbox"
                    checked={formData.ativo}
                    onChange={(e) => setFormData({ ...formData, ativo: e.target.checked })}
                  />
                  Cupom ativo
                </label>
              </div>

              <div className={styles.formActions}>
                <button
                  type="button"
                  onClick={() => {
                    setShowModal(false);
                    resetForm();
                  }}
                  className={styles.btnCancel}
                >
                  Cancelar
                </button>
                <button type="submit" className={styles.btnSubmit}>
                  {editingCupom ? 'Atualizar' : 'Criar'} Cupom
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

/* eslint-disable @typescript-eslint/no-explicit-any */
'use client';

import { Fragment, useEffect, useState } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { returnService } from '@/services/api';
import { Devolucao } from '@/types';
import { FiArrowLeft, FiRefreshCcw, FiCheckCircle, FiClock } from 'react-icons/fi';
import styles from './devolucoes.module.scss';

const API_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000/api';
const IMAGE_BASE_URL = API_URL.replace('/api', '');

export default function AdminDevolucoesPage() {
  const { user, loading: authLoading } = useAuth();
  const router = useRouter();
  const [devolucoes, setDevolucoes] = useState<Devolucao[]>([]);
  const [loading, setLoading] = useState(true);
  const [filtroStatus, setFiltroStatus] = useState('');
  const [statusDrafts, setStatusDrafts] = useState<Record<number, string>>({});
  const [decisaoDrafts, setDecisaoDrafts] = useState<Record<number, string>>({});
  const [instrucoesDrafts, setInstrucoesDrafts] = useState<Record<number, string>>({});
  const [expandedRows, setExpandedRows] = useState<Record<number, boolean>>({});

  const statusOptions = [
    { value: 'solicitado', label: 'Solicitado' },
    { value: 'em_analise', label: 'Em analise' },
    { value: 'aprovado', label: 'Aprovado' },
    { value: 'recusado', label: 'Recusado' },
    { value: 'recorre', label: 'Recorreu' },
    { value: 'concluido', label: 'Concluido' },
  ];

  useEffect(() => {
    if (!authLoading && (!user || !user.is_admin)) {
      router.push('/perfil');
    }
  }, [user, authLoading, router]);

  useEffect(() => {
    if (user && user.is_admin) {
      carregarDevolucoes();
    }
  }, [user, filtroStatus]);

  useEffect(() => {
    const drafts: Record<number, string> = {};
    const decisao: Record<number, string> = {};
    const instrucoes: Record<number, string> = {};
    const expanded: Record<number, boolean> = {};
    devolucoes.forEach((devolucao) => {
      drafts[devolucao.id] = devolucao.status;
      decisao[devolucao.id] = devolucao.admin_decisao || '';
      instrucoes[devolucao.id] = devolucao.admin_instrucoes || '';
      if (devolucao.justificativa_recorrencia || devolucao.observacoes || devolucao.admin_instrucoes) {
        expanded[devolucao.id] = true;
      }
    });
    setStatusDrafts(drafts);
    setDecisaoDrafts(decisao);
    setInstrucoesDrafts(instrucoes);
    setExpandedRows(expanded);
  }, [devolucoes]);

  const carregarDevolucoes = async () => {
    setLoading(true);
    try {
      const params = filtroStatus ? { status: filtroStatus } : {};
      const response = await returnService.getAll(params);
      if (response.success) {
        setDevolucoes(response.data || []);
      }
    } catch (error) {
      console.error('Erro ao carregar devolucoes:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleAtualizarStatus = async (devolucaoId: number, novoStatus: string) => {
    if (!novoStatus) return;

    const adminDecisao = decisaoDrafts[devolucaoId] || '';
    const adminInstrucoes = instrucoesDrafts[devolucaoId] || '';

    try {
      const response = await returnService.updateStatus(
        devolucaoId,
        novoStatus,
        adminDecisao,
        adminInstrucoes
      );
      if (response.success) {
        alert('Status atualizado com sucesso!');
        carregarDevolucoes();
      }
    } catch (error: any) {
      alert(error.message || 'Erro ao atualizar status');
    }
  };

  const handleStatusChange = (devolucaoId: number, value: string) => {
    setStatusDrafts((prev) => ({
      ...prev,
      [devolucaoId]: value,
    }));
  };

  const handleDecisaoChange = (devolucaoId: number, value: string) => {
    setDecisaoDrafts((prev) => ({
      ...prev,
      [devolucaoId]: value,
    }));
  };

  const handleInstrucoesChange = (devolucaoId: number, value: string) => {
    setInstrucoesDrafts((prev) => ({
      ...prev,
      [devolucaoId]: value,
    }));
  };

  const toggleExpanded = (devolucaoId: number) => {
    setExpandedRows((prev) => ({
      ...prev,
      [devolucaoId]: !prev[devolucaoId],
    }));
  };

  const total = devolucoes.length;
  const emAnalise = devolucoes.filter((d) => d.status === 'em_analise').length;
  const pendentes = devolucoes.filter((d) => d.status === 'solicitado').length;
  const aprovadas = devolucoes.filter((d) => d.status === 'aprovado').length;

  if (authLoading || loading) {
    return (
      <div className={styles.loading}>
        <div className="spinner-border" role="status"></div>
      </div>
    );
  }

  if (!user || !user.is_admin) {
    return null;
  }

  return (
    <div className={styles.adminDevolucoes}>
      <div className={styles.container}>
        <div className={styles.header}>
          <div className={styles.headerLeft}>
            <Link href="/admin" className={styles.backButton}>
              <FiArrowLeft /> Voltar
            </Link>
            <h1>Gerenciar Devolucoes</h1>
          </div>
        </div>

        <div className={styles.stats}>
          <div className={styles.statCard}>
            <FiRefreshCcw size={24} />
            <div>
              <p>Total</p>
              <h3>{total}</h3>
            </div>
          </div>
          <div className={styles.statCard}>
            <FiClock size={24} />
            <div>
              <p>Solicitadas</p>
              <h3>{pendentes}</h3>
            </div>
          </div>
          <div className={styles.statCard}>
            <FiClock size={24} />
            <div>
              <p>Em analise</p>
              <h3>{emAnalise}</h3>
            </div>
          </div>
          <div className={styles.statCard}>
            <FiCheckCircle size={24} />
            <div>
              <p>Aprovadas</p>
              <h3>{aprovadas}</h3>
            </div>
          </div>
        </div>

        <div className={styles.filters}>
          <select
            value={filtroStatus}
            onChange={(e) => setFiltroStatus(e.target.value)}
            className={styles.filterSelect}
          >
            <option value="">Todos os status</option>
            <option value="solicitado">Solicitado</option>
            <option value="em_analise">Em analise</option>
            <option value="aprovado">Aprovado</option>
            <option value="recusado">Recusado</option>
            <option value="recorre">Recorreu</option>
            <option value="concluido">Concluido</option>
          </select>
        </div>

        <div className={styles.tableContainer}>
          <table className={styles.table}>
            <thead>
              <tr>
                <th>ID</th>
                <th>Cliente</th>
                <th>Pedido</th>
                <th>Tipo</th>
                <th>Detalhes</th>
                <th>Resposta Admin</th>
                <th>Itens</th>
                <th>Anexos</th>
                <th>Status</th>
                <th>Data</th>
                <th>Acoes</th>
              </tr>
            </thead>
            <tbody>
              {devolucoes.map((devolucao) => (
                <Fragment key={devolucao.id}>
                  <tr>
                  <td>#{devolucao.id}</td>
                  <td>{devolucao.usuario_nome || 'N/A'}</td>
                  <td>
                    <Link href={`/pedidos/${devolucao.pedido_id}`} className={styles.linkButton}>
                      #{devolucao.pedido_id}
                    </Link>
                  </td>
                  <td>{devolucao.tipo}</td>
                  <td>
                    <button
                      type="button"
                      className={styles.detailsButton}
                      onClick={() => toggleExpanded(devolucao.id)}
                    >
                      {expandedRows[devolucao.id] ? 'Ocultar' : 'Ver'} detalhes
                    </button>
                  </td>
                  <td>
                    <div className={styles.adminResponse}>
                      <textarea
                        className={styles.textArea}
                        rows={2}
                        placeholder="Resumo da decisao"
                        value={decisaoDrafts[devolucao.id] || ''}
                        onChange={(event) => handleDecisaoChange(devolucao.id, event.target.value)}
                      />
                      <textarea
                        className={styles.textArea}
                        rows={2}
                        placeholder="Instrucoes para o cliente"
                        value={instrucoesDrafts[devolucao.id] || ''}
                        onChange={(event) => handleInstrucoesChange(devolucao.id, event.target.value)}
                      />
                    </div>
                  </td>
                  <td>
                    {devolucao.itens && devolucao.itens.length > 0 ? (
                      <div className={styles.detailsList}>
                        {devolucao.itens.map((item) => (
                          <div key={item.id} className={styles.detailItem}>
                            <span>{item.produto_nome || `Produto ${item.produto_id}`}</span>
                            <span>Qtd: {item.quantidade}</span>
                            {item.motivo_item && <span>Motivo: {item.motivo_item}</span>}
                          </div>
                        ))}
                      </div>
                    ) : (
                      <span className={styles.textMuted}>Sem itens</span>
                    )}
                  </td>
                  <td>
                    {devolucao.anexos && devolucao.anexos.length > 0 ? (
                      <div className={styles.detailsList}>
                        {devolucao.anexos.map((anexo) => {
                          const arquivoUrl = anexo.arquivo_url?.startsWith('http')
                            ? anexo.arquivo_url
                            : `${IMAGE_BASE_URL}${anexo.arquivo_url || ''}`;

                          return (
                            <a
                              key={anexo.id}
                              href={arquivoUrl}
                              target="_blank"
                              rel="noreferrer"
                              className={styles.linkButton}
                            >
                              {anexo.arquivo_nome || 'Anexo'}
                            </a>
                          );
                        })}
                      </div>
                    ) : (
                      <span className={styles.textMuted}>Sem anexos</span>
                    )}
                  </td>
                  <td>
                    <select
                      className={styles.statusSelect}
                      value={statusDrafts[devolucao.id] || devolucao.status}
                      onChange={(event) => handleStatusChange(devolucao.id, event.target.value)}
                    >
                      {statusOptions.map((option) => (
                        <option key={option.value} value={option.value}>
                          {option.label}
                        </option>
                      ))}
                    </select>
                  </td>
                  <td>{new Date(devolucao.data_criacao).toLocaleDateString('pt-BR')}</td>
                  <td>
                    <div className={styles.actions}>
                      <button
                        onClick={() => handleAtualizarStatus(devolucao.id, statusDrafts[devolucao.id] || devolucao.status)}
                        className={styles.btnEdit}
                      >
                        Atualizar
                      </button>
                    </div>
                  </td>
                  </tr>
                  {expandedRows[devolucao.id] && (
                    <tr className={styles.expandedRow}>
                      <td colSpan={11}>
                        <div className={styles.detailsPanel}>
                          <div className={styles.detailsGrid}>
                            <div>
                              <div className={styles.detailsLabel}>Motivo</div>
                              <div className={styles.detailsValue}>{devolucao.motivo}</div>
                            </div>
                            <div>
                              <div className={styles.detailsLabel}>Justificativa</div>
                              <div className={styles.detailsValue}>{devolucao.justificativa}</div>
                            </div>
                            {devolucao.observacoes && (
                              <div>
                                <div className={styles.detailsLabel}>Observacoes</div>
                                <div className={styles.detailsValue}>{devolucao.observacoes}</div>
                              </div>
                            )}
                            {devolucao.justificativa_recorrencia && (
                              <div>
                                <div className={styles.detailsLabel}>Recorrencia</div>
                                <div className={styles.detailsValue}>{devolucao.justificativa_recorrencia}</div>
                              </div>
                            )}
                          </div>
                        </div>
                      </td>
                    </tr>
                  )}
                </Fragment>
              ))}
            </tbody>
          </table>

          {devolucoes.length === 0 && (
            <div className={styles.empty}>
              <p>Nenhuma solicitacao encontrada</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

/* eslint-disable @typescript-eslint/no-explicit-any */
'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useRouter } from 'next/navigation';
import { orderService } from '@/services/api';
import Link from 'next/link';
import { FiArrowLeft, FiPackage, FiCheckCircle, FiTruck, FiX } from 'react-icons/fi';
import styles from './pedidos.module.scss';

type AbaAtiva = 'todos' | 'retiradas' | 'reembolsos';

interface PedidoAdmin {
  id: number;
  pedido_id?: number;
  usuario_nome?: string;
  data_pedido?: string;
  valor_total?: number;
  total?: number;
  forma_pagamento?: string;
  asaas_payment_status?: string;
  status: string;
  pedido_status?: string;
  codigo_rastreio?: string;
  superfrete_pedido_id?: string | number;
  superfrete_etiqueta_url?: string;
  retirada_codigo?: string;
  pagamento_verificado?: boolean;
  motivo?: string;
  reembolso_status?: string;
  entrega_tipo?: string;
}

interface ReembolsoAdmin {
  id?: number;
  pedido_id: number;
  usuario_nome?: string;
  data_pedido?: string;
  valor_total?: number;
  total?: number;
  forma_pagamento?: string;
  asaas_payment_status?: string;
  pedido_status?: string;
  status?: string;
  motivo?: string;
  reembolso_status?: string;
  retirada_codigo?: string;
  codigo_rastreio?: string;
  superfrete_pedido_id?: string | number;
  superfrete_etiqueta_url?: string;
}

interface FormRetirada {
  codigo: string;
  nome_retirada: string;
  observacao: string;
}

const PAYMENT_LABELS: Record<string, string> = {
  pix: 'PIX',
  cartao: 'Cartão de Crédito',
  credito: 'Cartão de Crédito',
  debito: 'Cartão de Débito',
  boleto: 'Boleto',
  local: 'Pagamento na retirada',
};

const formatarPagamento = (formaPagamento?: string) => {
  if (!formaPagamento) return 'N/A';
  return PAYMENT_LABELS[formaPagamento] || formaPagamento;
};

const formatarValor = (valor?: number | string | null) => `R$ ${Number(valor || 0).toFixed(2)}`;

const obterPedidoId = (pedido: PedidoAdmin | ReembolsoAdmin, abaAtiva: AbaAtiva) => (
  abaAtiva === 'reembolsos' ? pedido.pedido_id : (pedido as PedidoAdmin).id
);

export default function AdminPedidosPage() {
  const { user, loading: authLoading } = useAuth();
  const router = useRouter();
  const [pedidos, setPedidos] = useState<PedidoAdmin[]>([]);
  const [retiradas, setRetiradas] = useState<PedidoAdmin[]>([]);
  const [reembolsos, setReembolsos] = useState<ReembolsoAdmin[]>([]);
  const [loading, setLoading] = useState(true);
  const [filtroStatus, setFiltroStatus] = useState('');
  const [statusDrafts, setStatusDrafts] = useState<Record<number, string>>({});
  const [abaAtiva, setAbaAtiva] = useState<AbaAtiva>('todos');
  const [modalAberto, setModalAberto] = useState(false);
  const [pedidoSelecionado, setPedidoSelecionado] = useState<PedidoAdmin | null>(null);
  const [formRetirada, setFormRetirada] = useState<FormRetirada>({
    codigo: '',
    nome_retirada: '',
    observacao: '',
  });
  const [erroModal, setErroModal] = useState('');
  const [loadingModal, setLoadingModal] = useState(false);

  const statusOptions = [
    { value: 'pendente', label: 'Pendente' },
    { value: 'pendente_pagamento_retirada', label: 'Aguardando pagamento (retirada)' },
    { value: 'aguardando_pagamento_retirada', label: 'Aguardando pagamento (retirada)' },
    { value: 'pronto_para_retirada', label: 'Pronto para retirada' },
    { value: 'retirado', label: 'Retirado' },
    { value: 'pago', label: 'Pago' },
    { value: 'processando', label: 'Processando' },
    { value: 'enviado', label: 'Enviado' },
    { value: 'devolucao', label: 'Devolução' },
    { value: 'devolvido', label: 'Devolvido' },
    { value: 'entregue', label: 'Entregue' },
    { value: 'cancelado', label: 'Cancelado' },
  ];

  useEffect(() => {
    if (!authLoading && (!user || !user.is_admin)) {
      router.push('/perfil');
    }
  }, [user, authLoading, router]);

  useEffect(() => {
    if (user && user.is_admin) {
      if (abaAtiva === 'retiradas') {
        carregarRetiradas();
      } else if (abaAtiva === 'reembolsos') {
        carregarReembolsos();
      } else {
        carregarPedidos();
      }
    }
  }, [user, filtroStatus, abaAtiva]);

  useEffect(() => {
    if (abaAtiva === 'reembolsos') {
      setStatusDrafts({});
      return;
    }

    const drafts: Record<number, string> = {};
    const base = abaAtiva === 'retiradas' ? retiradas : pedidos;
    base.forEach((pedido) => {
      drafts[pedido.id] = pedido.status;
    });
    setStatusDrafts(drafts);
  }, [pedidos, retiradas, abaAtiva]);

  const carregarPedidos = async () => {
    setLoading(true);
    try {
      const params = filtroStatus ? { status: filtroStatus } : {};
      const response = await orderService.getAll(params);
      if (response.success) {
        setPedidos((response.data || []) as PedidoAdmin[]);
      }
    } catch (error) {
      console.error('Erro ao carregar pedidos:', error);
    } finally {
      setLoading(false);
    }
  };

  const carregarRetiradas = async () => {
    setLoading(true);
    try {
      const params = filtroStatus ? { status: filtroStatus } : {};
      const response = await orderService.getRetiradasAdmin(params);
      if (response.success) {
        setRetiradas((response.data || []) as PedidoAdmin[]);
      }
    } catch (error) {
      console.error('Erro ao carregar retiradas:', error);
    } finally {
      setLoading(false);
    }
  };

  const carregarReembolsos = async () => {
    setLoading(true);
    try {
      const response = await orderService.getReembolsosAdmin();
      if (response.success) {
        setReembolsos((response.data || []) as ReembolsoAdmin[]);
      }
    } catch (error) {
      console.error('Erro ao carregar fila de reembolsos:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleAtualizarStatus = async (pedidoId: number | undefined, novoStatus: string) => {
    if (!pedidoId) return;
    if (!novoStatus) return;

    try {
      const response = await orderService.updateStatus(pedidoId, novoStatus);
      if (response.success) {
        alert('Status atualizado com sucesso!');
        carregarPedidos();
      }
    } catch (error: any) {
      alert(error.message || 'Erro ao atualizar status');
    }
  };

  const handleStatusChange = (pedidoId: number, value: string) => {
    setStatusDrafts((prev) => ({
      ...prev,
      [pedidoId]: value,
    }));
  };

  const handleAdicionarRastreio = async (pedidoId: number) => {
    const codigo = prompt('Digite o código de rastreio:');
    if (!codigo) return;

    try {
      const response = await orderService.addTracking(pedidoId, codigo);
      if (response.success) {
        alert('Código de rastreio adicionado com sucesso!');
        carregarPedidos();
      }
    } catch (error: any) {
      alert(error.message || 'Erro ao adicionar rastreio');
    }
  };

  const handleConfirmarRetirada = (pedido: PedidoAdmin) => {
    setPedidoSelecionado(pedido);
    setFormRetirada({
      codigo: '',
      nome_retirada: pedido.usuario_nome || '',
      observacao: '',
    });
    setErroModal('');
    setModalAberto(true);
  };

  const handleSubmeterRetirada = async () => {
    if (!pedidoSelecionado) {
      setErroModal('Pedido não selecionado');
      return;
    }

    if (!formRetirada.codigo.trim()) {
      setErroModal('Digite o código de retirada');
      return;
    }

    if (!formRetirada.nome_retirada.trim()) {
      setErroModal('Digite o nome de quem retirou');
      return;
    }

    setLoadingModal(true);
    setErroModal('');

    try {
      const response = await orderService.confirmarRetirada(pedidoSelecionado.id, {
        codigo: formRetirada.codigo,
        nome_retirada: formRetirada.nome_retirada,
        observacao: formRetirada.observacao || undefined,
      });

      if (response.success) {
        alert('Retirada confirmada com sucesso!');
        setModalAberto(false);
        carregarRetiradas();
      } else {
        setErroModal(response.message || 'Erro ao confirmar retirada');
      }
    } catch (error: any) {
      setErroModal(error.message || 'Erro ao confirmar retirada');
    } finally {
      setLoadingModal(false);
    }
  };

  const fecharModal = () => {
    setModalAberto(false);
    setPedidoSelecionado(null);
    setFormRetirada({ codigo: '', nome_retirada: '', observacao: '' });
    setErroModal('');
  };

  const handleImprimirEtiqueta = async (pedidoId: number, etiquetaUrl?: string) => {
    if (etiquetaUrl) {
      window.open(etiquetaUrl, '_blank', 'noopener,noreferrer');
      return;
    }

    try {
      const response = await orderService.printLabel(pedidoId);
      const url = response?.data?.url;

      if (url) {
        setPedidos((prev) =>
          prev.map((pedido) =>
            pedido.id === pedidoId ? { ...pedido, superfrete_etiqueta_url: url } : pedido
          )
        );
        window.open(url, '_blank', 'noopener,noreferrer');
      } else {
        alert('Link da etiqueta nao encontrado.');
      }
    } catch (error: any) {
      alert(error.message || 'Erro ao gerar link da etiqueta');
    }
  };

  const handleProcessarReembolso = async (pedidoId: number) => {
    const confirmar = window.confirm(`Confirmar solicitação de reembolso manual no Asaas para o pedido #${pedidoId}?`);
    if (!confirmar) return;

    try {
      const response = await orderService.processarReembolsoAdmin(pedidoId);
      if (response.success) {
        alert(response.message || 'Reembolso solicitado com sucesso');
        carregarReembolsos();
        carregarPedidos();
      }
    } catch (error: any) {
      alert(error.message || 'Erro ao processar reembolso');
    }
  };

  const basePedidos: Array<PedidoAdmin | ReembolsoAdmin> = abaAtiva === 'retiradas'
    ? retiradas
    : (abaAtiva === 'reembolsos' ? reembolsos : pedidos);
  const pedidosFiltrados = basePedidos;
  const totalPedidos = basePedidos.length;
  const pedidosPendentes = abaAtiva === 'reembolsos'
    ? basePedidos.filter((p) => p.reembolso_status === 'pendente').length
    : basePedidos.filter((p) => p.status === 'pendente').length;
  const pedidosEnviados = abaAtiva === 'reembolsos'
    ? basePedidos.filter((p) => p.pedido_status === 'cancelado').length
    : basePedidos.filter((p) => p.status === 'enviado').length;
  const valorTotal = basePedidos.reduce((acc, p) => acc + Number(p.valor_total ?? p.total ?? 0), 0);

  if (authLoading || loading) {
    return (
      <div className={styles.loading}>
        <div className="spinner-border" role="status"></div>
      </div>
    );
  }

  if (!user || !user.is_admin) {
    return null;
  }

  return (
    <div className={styles.adminPedidos}>
      <div className={styles.container}>
        <div className={styles.header}>
          <div className={styles.headerLeft}>
            <Link href="/admin" className={styles.backButton}>
              <FiArrowLeft /> Voltar
            </Link>
            <h1>Gerenciar Pedidos</h1>
          </div>
        </div>

        <div className={styles.filters}>
          <button
            className={abaAtiva === 'todos' ? styles.btnPrimary : styles.btnEdit}
            onClick={() => setAbaAtiva('todos')}
          >
            Todos os pedidos
          </button>
          <button
            className={abaAtiva === 'retiradas' ? styles.btnPrimary : styles.btnEdit}
            onClick={() => setAbaAtiva('retiradas')}
          >
            Retiradas no local
          </button>
          <button
            className={abaAtiva === 'reembolsos' ? styles.btnPrimary : styles.btnEdit}
            onClick={() => setAbaAtiva('reembolsos')}
          >
            Reembolsos
          </button>
        </div>

        <div className={styles.stats}>
          <div className={styles.statCard}>
            <FiPackage size={24} />
            <div>
              <p>Total de Pedidos</p>
              <h3>{totalPedidos}</h3>
            </div>
          </div>
          <div className={styles.statCard}>
            <FiPackage size={24} />
            <div>
              <p>Pendentes</p>
              <h3>{pedidosPendentes}</h3>
            </div>
          </div>
          <div className={styles.statCard}>
            <FiTruck size={24} />
            <div>
              <p>Enviados</p>
              <h3>{pedidosEnviados}</h3>
            </div>
          </div>
          <div className={styles.statCard}>
            <FiCheckCircle size={24} />
            <div>
              <p>Valor Total</p>
              <h3>R$ {Number(valorTotal || 0).toFixed(2)}</h3>
            </div>
          </div>
        </div>

        {abaAtiva !== 'reembolsos' && (
          <div className={styles.filters}>
            <select
              value={filtroStatus}
              onChange={(e) => setFiltroStatus(e.target.value)}
              className={styles.filterSelect}
            >
              <option value="">Todos os status</option>
              <option value="pendente">Pendente</option>
              <option value="pendente_pagamento_retirada">Aguardando pagamento (retirada)</option>
              <option value="aguardando_pagamento_retirada">Aguardando pagamento (retirada)</option>
              <option value="pronto_para_retirada">Pronto para retirada</option>
              <option value="retirado">Retirado</option>
              <option value="pago">Pago</option>
              <option value="processando">Processando</option>
              <option value="enviado">Enviado</option>
              <option value="devolucao">Devolução</option>
              <option value="devolvido">Devolvido</option>
              <option value="entregue">Entregue</option>
              <option value="cancelado">Cancelado</option>
            </select>
          </div>
        )}

        <div className={styles.tableContainer}>
          <table className={styles.table} data-testid="orders-table">
            <thead>
              <tr>
                <th>ID</th>
                <th>Código retirada</th>
                <th>Cliente</th>
                <th>Data</th>
                <th>Valor</th>
                <th>Pagamento</th>
                <th>Status Asaas</th>
                <th>Status</th>
                <th>Rastreio</th>
                <th>Etiqueta</th>
                <th>Ações</th>
              </tr>
            </thead>
            <tbody>
              {pedidosFiltrados.map((pedido, index) => (
                <tr
                  key={`pedido-${obterPedidoId(pedido, abaAtiva) ?? index}`}
                >
                  <td>#{obterPedidoId(pedido, abaAtiva)}</td>
                  <td>{abaAtiva === 'reembolsos' ? '-' : (pedido.retirada_codigo || '-')}</td>
                  <td>{pedido.usuario_nome || 'N/A'}</td>
                  <td>{pedido.data_pedido ? new Date(pedido.data_pedido).toLocaleDateString('pt-BR') : '-'}</td>
                  <td>{formatarValor(pedido.valor_total ?? pedido.total ?? 0)}</td>
                  <td>
                    <span className={styles.paymentMethod}>
                      {formatarPagamento(pedido.forma_pagamento)}
                    </span>
                  </td>
                  <td>{pedido.asaas_payment_status || 'N/A'}</td>
                  <td>
                    {abaAtiva === 'reembolsos' ? (
                      <span>{pedido.pedido_status || 'cancelado'}</span>
                    ) : (
                      <select
                        className={styles.statusSelect}
                        value={statusDrafts[(pedido as PedidoAdmin).id] || pedido.status}
                        onChange={(event) => handleStatusChange((pedido as PedidoAdmin).id, event.target.value)}
                      >
                        {statusOptions.map((option) => (
                          <option key={option.value} value={option.value}>
                            {option.label}
                          </option>
                        ))}
                      </select>
                    )}
                  </td>
                  <td>
                    {abaAtiva === 'reembolsos' ? (
                      <span className={styles.textMuted}>{pedido.motivo || 'pendente'}</span>
                    ) : pedido.codigo_rastreio || (
                      <span className={styles.textMuted}>Sem rastreio</span>
                    )}
                  </td>
                  <td>
                    {abaAtiva === 'reembolsos' ? (
                      <span className={styles.textMuted}>{pedido.reembolso_status || 'pendente'}</span>
                    ) : pedido.superfrete_pedido_id ? (
                      <button
                        onClick={() => handleImprimirEtiqueta((pedido as PedidoAdmin).id, pedido.superfrete_etiqueta_url)}
                        className={styles.btnPrimary}
                      >
                        {pedido.superfrete_etiqueta_url ? 'Imprimir' : 'Gerar link'}
                      </button>
                    ) : (
                      <span className={styles.textMuted}>Sem etiqueta</span>
                    )}
                  </td>
                  <td>
                    <div className={styles.actions}>
                      <Link href={`/pedidos/${abaAtiva === 'reembolsos' ? pedido.pedido_id : pedido.id}`} className={styles.btnView}>
                        Ver
                      </Link>
                      {abaAtiva === 'reembolsos' && (
                        <button
                          onClick={() => handleProcessarReembolso(pedido.pedido_id as number)}
                          className={styles.btnPrimary}
                        >
                          Reembolsar
                        </button>
                      )}
                      {abaAtiva === 'retiradas' && pedido.status === 'pronto_para_retirada' && (
                        <button
                          onClick={() => handleConfirmarRetirada(pedido as PedidoAdmin)}
                          className={styles.btnPrimary}
                        >
                          Confirmar retirada
                        </button>
                      )}
                      {abaAtiva !== 'reembolsos' && (
                        <button
                          onClick={() => handleAtualizarStatus((pedido as PedidoAdmin).id, statusDrafts[(pedido as PedidoAdmin).id] || pedido.status || '')}
                          className={styles.btnEdit}
                        >
                          Atualizar
                        </button>
                      )}
                      {abaAtiva !== 'reembolsos' && (
                        <button
                          onClick={() => handleAdicionarRastreio((pedido as PedidoAdmin).id)}
                          className={styles.btnPrimary}
                        >
                          Rastreio
                        </button>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          {pedidosFiltrados.length === 0 && (
            <div className={styles.empty}>
              <p>Nenhum pedido encontrado</p>
            </div>
          )}
        </div>
      </div>

      {/* Modal Confirmar Retirada */}
      {modalAberto && pedidoSelecionado && (
        <div className={styles.modalOverlay}>
          <div className={styles.modal}>
            <div className={styles.modalHeader}>
              <h2>Confirmar Retirada - Pedido #{pedidoSelecionado.id}</h2>
              <button onClick={fecharModal} className={styles.closeButton}>
                <FiX size={24} />
              </button>
            </div>

            <div className={styles.modalBody}>
              {/* Resumo do Pedido */}
              <div className={styles.pedidoResumo}>
                <p><strong>Código de retirada:</strong> {pedidoSelecionado.retirada_codigo || 'Ainda não gerado'}</p>
                <p><strong>Cliente:</strong> {pedidoSelecionado.usuario_nome}</p>
                <p><strong>Data:</strong> {pedidoSelecionado.data_pedido ? new Date(pedidoSelecionado.data_pedido).toLocaleDateString('pt-BR') : '-'}</p>
                <p><strong>Valor:</strong> {formatarValor(pedidoSelecionado.valor_total ?? pedidoSelecionado.total ?? 0)}</p>
                <p><strong>Forma de Pagamento:</strong> {formatarPagamento(pedidoSelecionado.forma_pagamento)}</p>
                <p><strong>Pagamento verificado:</strong> {pedidoSelecionado.pagamento_verificado ? 'Sim' : 'Não'}</p>
                {pedidoSelecionado.asaas_payment_status && (
                  <p><strong>Status Asaas:</strong> {pedidoSelecionado.asaas_payment_status}</p>
                )}
              </div>

              {/* Formulário */}
              <div className={styles.formGroup}>
                <label htmlFor="codigo">Código de Retirada *</label>
                <input
                  id="codigo"
                  type="text"
                  placeholder="Digite ou escaneie o código (ex: 01123456)"
                  value={formRetirada.codigo}
                  onChange={(e) => setFormRetirada({ ...formRetirada, codigo: e.target.value.toUpperCase() })}
                  disabled={loadingModal}
                  autoFocus
                  maxLength={8}
                />
                <small>Digite exatamente 8 dígitos</small>
              </div>

              <div className={styles.formGroup}>
                <label htmlFor="nome">Nome de quem retirou *</label>
                <input
                  id="nome"
                  type="text"
                  placeholder="Nome do cliente ou terceiro que retira"
                  value={formRetirada.nome_retirada}
                  onChange={(e) => setFormRetirada({ ...formRetirada, nome_retirada: e.target.value })}
                  disabled={loadingModal}
                />
              </div>

              <div className={styles.formGroup}>
                <label htmlFor="observacao">Observação Interna (opcional)</label>
                <textarea
                  id="observacao"
                  placeholder="Anotações sobre a retirada (ex: cliente apresentou documento, foi terceiro, etc)"
                  value={formRetirada.observacao}
                  onChange={(e) => setFormRetirada({ ...formRetirada, observacao: e.target.value })}
                  disabled={loadingModal}
                  rows={3}
                />
              </div>

              {erroModal && (
                <div className={styles.errorAlert}>
                  <strong>Erro:</strong> {erroModal}
                </div>
              )}
            </div>

            <div className={styles.modalFooter}>
              <button
                onClick={fecharModal}
                disabled={loadingModal}
                className={styles.btnSecondary}
              >
                Cancelar
              </button>
              <button
                onClick={handleSubmeterRetirada}
                disabled={loadingModal}
                className={styles.btnPrimary}
              >
                {loadingModal ? 'Processando...' : 'Confirmar Retirada'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

/* eslint-disable @typescript-eslint/no-explicit-any */
'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useToast } from '@/contexts/ToastContext';
import { useRouter, useParams } from 'next/navigation';
import { productService, categoryService, tipoProdutoService } from '@/services/api';
import Link from 'next/link';
import { FiArrowLeft, FiSave } from 'react-icons/fi';
import styles from './produto-form.module.scss';

const API_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000/api';

export default function ProdutoFormPage() {
  const { user, loading: authLoading } = useAuth();
  const { success, error: showError } = useToast();
  const router = useRouter();
  const params = useParams();
  const produtoId = params?.id as string;
  const isEditing = !!produtoId && produtoId !== 'novo';

  const [loading, setLoading] = useState(false);
  const [categorias, setCategorias] = useState<any[]>([]);
  const [tiposProduto, setTiposProduto] = useState<any[]>([]);
  const [uploading, setUploading] = useState(false);

  const [formData, setFormData] = useState({
    nome: '',
    descricao: '',
    preco: 0,
    preco_pix: 0,
    preco_debito: 0,
    preco_credito: 0,
    preco_boleto: 0,
    preco_original: 0,
    parcelas_maximas: 3,
    desconto_percentual: 0,
    categoria_id: '',
    categoria_ids: [] as string[],
    estoque: 0,
    imagens: [] as string[],
    cores_disponiveis: [] as string[],
    tamanhos_disponiveis: [] as string[],
    tipo_produto_id: null as number | null,
    ativo: true,
  });

  const [usarMesmoValorPagamentos, setUsarMesmoValorPagamentos] = useState(true);

  const [imagemInput, setImagemInput] = useState('');
  const [imagemTipo, setImagemTipo] = useState<'url' | 'upload'>('url');
  const [corInput, setCorInput] = useState('');
  const [tamanhoInput, setTamanhoInput] = useState('');

  useEffect(() => {
    if (!authLoading && (!user || !user.is_admin)) {
      router.push('/perfil');
    }
  }, [user, authLoading, router]);

  useEffect(() => {
    if (user && user.is_admin) {
      carregarCategorias();
      carregarTiposProduto();
      if (isEditing) {
        carregarProduto();
      }
    }
  }, [user, isEditing, produtoId]);

  const carregarCategorias = async () => {
    try {
      const response = await categoryService.getAllAdmin();
      if (response.success) {
        setCategorias(response.data || []);
      }
    } catch (error) {
      console.error('Erro ao carregar categorias:', error);
    }
  };

  const carregarTiposProduto = async () => {
    try {
      const response = await tipoProdutoService.getAll();
      if (response.success) {
        setTiposProduto(response.data || []);
      }
    } catch (error) {
      console.error('Erro ao carregar tipos de produto:', error);
    }
  };

  const carregarProduto = async () => {
    setLoading(true);
    try {
      const response = await productService.getById(parseInt(produtoId));
      if (response.success && response.data) {
        const produto = response.data;
        const categoriaIds = Array.isArray(produto.categoria_ids) && produto.categoria_ids.length > 0
          ? produto.categoria_ids.map((id: number) => String(id))
          : produto.categoria_id
          ? [String(produto.categoria_id)]
          : [];

        const precoBase = produto.preco || 0;
        const precoCredito = produto.preco_credito ?? precoBase;
        const precoDebito = produto.preco_debito ?? precoBase;
        const precoBoleto = produto.preco_boleto ?? precoBase;

        setFormData({
          nome: produto.nome || '',
          descricao: produto.descricao || '',
          preco: produto.preco || 0,
          preco_pix: produto.preco_pix ?? precoBase,
          preco_debito: precoDebito,
          preco_credito: precoCredito,
          preco_boleto: precoBoleto,
          preco_original: produto.preco_original || 0,
          parcelas_maximas: produto.parcelas_maximas || 3,
          desconto_percentual: produto.desconto_percentual || 0,
          categoria_id: categoriaIds[0] || '',
          categoria_ids: categoriaIds,
          estoque: produto.estoque || 0,
          imagens: produto.imagens || [],
          cores_disponiveis: produto.cores_disponiveis || [],
          tamanhos_disponiveis: produto.tamanhos_disponiveis || [],
          tipo_produto_id: produto.tipo_produto_id || null,
          ativo: produto.ativo !== false,
        });

        setUsarMesmoValorPagamentos(precoCredito === precoDebito && precoCredito === precoBoleto);
      }
    } catch (error) {
      console.error('Erro ao carregar produto:', error);
      alert('Erro ao carregar produto');
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.nome || !formData.preco || formData.categoria_ids.length === 0) {
      showError('Preencha os campos obrigatórios: Nome, Preço e Categoria');
      return;
    }

    setLoading(true);
    try {
      const categoriaIds = formData.categoria_ids.map((id) => parseInt(id, 10)).filter((id) => !Number.isNaN(id));
      const data = {
        ...formData,
        categoria_id: categoriaIds[0] || parseInt(formData.categoria_id, 10),
        categoria_ids: categoriaIds,
        preco: parseFloat(formData.preco.toString()),
        preco_pix: formData.preco_pix > 0 ? parseFloat(formData.preco_pix.toString()) : parseFloat(formData.preco.toString()),
        preco_debito: formData.preco_debito > 0 ? parseFloat(formData.preco_debito.toString()) : parseFloat(formData.preco.toString()),
        preco_credito: formData.preco_credito > 0 ? parseFloat(formData.preco_credito.toString()) : parseFloat(formData.preco.toString()),
        preco_boleto: formData.preco_boleto > 0 ? parseFloat(formData.preco_boleto.toString()) : parseFloat(formData.preco.toString()),
        preco_original: formData.preco_original && formData.preco_original > 0 ? parseFloat(formData.preco_original.toString()) : null,
        parcelas_maximas: parseInt(formData.parcelas_maximas.toString(), 10) || 3,
        desconto_percentual: parseFloat(formData.desconto_percentual.toString()) || 0,
        estoque: parseInt(formData.estoque.toString()),
      };

      if (isEditing) {
        const response = await productService.update(parseInt(produtoId), data);
        if (response.success) {
          success('Produto atualizado com sucesso!');
          router.push('/admin/produtos');
        }
      } else {
        const response = await productService.create(data);
        if (response.success) {
          success('Produto criado com sucesso!');
          router.push('/admin/produtos');
        }
      }
    } catch (error: any) {
      showError(error.message || 'Erro ao salvar produto');
    } finally {
      setLoading(false);
    }
  };

  const adicionarImagem = () => {
    if (imagemInput.trim()) {
      setFormData({
        ...formData,
        imagens: [...formData.imagens, imagemInput.trim()],
      });
      setImagemInput('');
    }
  };

  const handleUploadImagem = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Validar tipo de arquivo
    const allowedTypes = ['image/jpeg', 'image/jpg', 'image/png', 'image/gif', 'image/webp'];
    if (!allowedTypes.includes(file.type)) {
      showError('Tipo de arquivo não suportado. Use apenas imagens (JPEG, PNG, GIF, WEBP).');
      return;
    }

    // Validar tamanho (5MB)
    if (file.size > 5 * 1024 * 1024) {
      showError('Arquivo muito grande. O tamanho máximo é 5MB.');
      return;
    }

    setUploading(true);
    try {
      const formDataUpload = new FormData();
      formDataUpload.append('imagem', file);

      const token = localStorage.getItem('token');
      const response = await fetch(`${API_URL}/produtos/upload-imagem`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
        },
        body: formDataUpload,
      });

      const data = await response.json();

      if (data.success && data.data.url) {
        // Adicionar a URL da imagem ao array de imagens
        const imageUrl = data.data.url.startsWith('http') 
          ? data.data.url 
          : `${API_URL.replace('/api', '')}${data.data.url}`;

        setFormData(prev => ({
          ...prev,
          imagens: [...prev.imagens, imageUrl],
        }));
        success('Imagem enviada com sucesso!');
      } else {
        showError(data.message || 'Erro ao fazer upload da imagem');
      }
    } catch (error: any) {
      console.error('Erro ao fazer upload:', error);
      showError('Erro ao fazer upload da imagem');
    } finally {
      setUploading(false);
      // Limpar o input file
      e.target.value = '';
    }
  };

  const removerImagem = (index: number) => {
    setFormData({
      ...formData,
      imagens: formData.imagens.filter((_, i) => i !== index),
    });
  };

  const adicionarCor = () => {
    if (corInput.trim() && !formData.cores_disponiveis.includes(corInput.trim())) {
      setFormData({
        ...formData,
        cores_disponiveis: [...formData.cores_disponiveis, corInput.trim()],
      });
      setCorInput('');
    }
  };

  const removerCor = (index: number) => {
    setFormData({
      ...formData,
      cores_disponiveis: formData.cores_disponiveis.filter((_, i) => i !== index),
    });
  };

  const adicionarTamanho = () => {
    if (tamanhoInput.trim() && !formData.tamanhos_disponiveis.includes(tamanhoInput.trim())) {
      setFormData({
        ...formData,
        tamanhos_disponiveis: [...formData.tamanhos_disponiveis, tamanhoInput.trim()],
      });
      setTamanhoInput('');
    }
  };

  const removerTamanho = (index: number) => {
    setFormData({
      ...formData,
      tamanhos_disponiveis: formData.tamanhos_disponiveis.filter((_, i) => i !== index),
    });
  };

  const handleCreditoChange = (valor: number) => {
    if (usarMesmoValorPagamentos) {
      setFormData(prev => ({
        ...prev,
        preco_credito: valor,
        preco_debito: valor,
        preco_boleto: valor,
      }));
      return;
    }

    setFormData(prev => ({
      ...prev,
      preco_credito: valor,
    }));
  };

  const handleToggleMesmoValor = (checked: boolean) => {
    setUsarMesmoValorPagamentos(checked);
    if (checked) {
      setFormData(prev => ({
        ...prev,
        preco_debito: prev.preco_credito || prev.preco,
        preco_boleto: prev.preco_credito || prev.preco,
      }));
    }
  };

  // Calcular desconto automaticamente
  useEffect(() => {
    if (formData.preco_original > 0 && formData.preco > 0) {
      const desconto = ((formData.preco_original - formData.preco) / formData.preco_original) * 100;
      setFormData(prev => ({ ...prev, desconto_percentual: Math.round(desconto * 100) / 100 }));
    }
  }, [formData.preco, formData.preco_original]);

  if (authLoading || (isEditing && loading)) {
    return (
      <div className={styles.loading}>
        <div className="spinner-border" role="status"></div>
      </div>
    );
  }

  if (!user || !user.is_admin) {
    return null;
  }

  return (
    <div className={styles.produtoForm}>
      <div className={styles.container}>
        <div className={styles.header}>
          <Link href="/admin/produtos" className={styles.backButton}>
            <FiArrowLeft /> Voltar para Produtos
          </Link>
          <h1>{isEditing ? 'Editar Produto' : 'Novo Produto'}</h1>
        </div>

        <form onSubmit={handleSubmit} className={styles.form}>
          <div className={styles.formCard}>
            <h2>Informações Básicas</h2>

            <div className={styles.formGroup}>
              <label>Nome do Produto *</label>
              <input
                type="text"
                value={formData.nome}
                onChange={(e) => setFormData({ ...formData, nome: e.target.value })}
                required
                placeholder="Ex: Camiseta Básica"
              />
            </div>

            <div className={styles.formGroup}>
              <label>Descrição</label>
              <textarea
                value={formData.descricao}
                onChange={(e) => setFormData({ ...formData, descricao: e.target.value })}
                placeholder="Descreva o produto..."
                rows={5}
              />
            </div>

            <div className={styles.formGroup}>
              <label>Categorias *</label>
              <select
                multiple
                value={formData.categoria_ids}
                onChange={(e) => {
                  const selected = Array.from(e.target.selectedOptions).map((opt) => opt.value);
                  setFormData({
                    ...formData,
                    categoria_ids: selected,
                    categoria_id: selected[0] || '',
                  });
                }}
                required
              >
                {categorias.map((cat) => (
                  <option key={cat.id} value={cat.id}>
                    {cat.nome}
                  </option>
                ))}
              </select>
              <small>Segure Ctrl (Windows) para selecionar mais de uma.</small>
            </div>

            <div className={styles.formGroup}>
              <label>Tipo de Produto (Configuração de Frete)</label>
              <select
                value={formData.tipo_produto_id || ''}
                onChange={(e) => setFormData({
                  ...formData,
                  tipo_produto_id: e.target.value ? parseInt(e.target.value) : null
                })}
              >
                <option value="">Usar configuração padrão (Fallback)</option>
                {tiposProduto.map((tipo) => (
                  <option key={tipo.id} value={tipo.id}>
                    {tipo.nome} ({tipo.codigo})
                  </option>
                ))}
              </select>
              <small>Define como o produto será empacotado para cálculo de frete</small>
            </div>
          </div>

          <div className={styles.formCard}>
            <h2>Preços e Promoção</h2>

            <div className={styles.formRow}>
              <div className={styles.formGroup}>
                <label>Preço Atual (R$) *</label>
                <input
                  type="number"
                  step="0.01"
                  min="0"
                  value={formData.preco}
                  onChange={(e) => setFormData({ ...formData, preco: parseFloat(e.target.value) })}
                  required
                  placeholder="0.00"
                />
              </div>

              <div className={styles.formGroup}>
                <label>Preço Original (R$)</label>
                <input
                  type="number"
                  step="0.01"
                  min="0"
                  value={formData.preco_original || ''}
                  onChange={(e) => {
                    const val = e.target.value;
                    setFormData({ 
                      ...formData, 
                      preco_original: val && val.trim() ? parseFloat(val) : 0 
                    });
                  }}
                  placeholder="0.00"
                />
                <small>Deixe em branco se não houver promoção</small>
              </div>

              <div className={styles.formGroup}>
                <label>Desconto (%)</label>
                <input
                  type="number"
                  step="0.01"
                  value={formData.desconto_percentual}
                  readOnly
                  disabled
                />
                <small>Calculado automaticamente</small>
              </div>
            </div>

            <div className={styles.formGroup}>
              <div className={styles.checkboxRow}>
                <input
                  type="checkbox"
                  checked={usarMesmoValorPagamentos}
                  onChange={(e) => handleToggleMesmoValor(e.target.checked)}
                  id="mesmo-valor-pagamentos"
                />
                <label htmlFor="mesmo-valor-pagamentos">
                  Usa o mesmo valor no credito, debito e boleto
                </label>
              </div>
            </div>

            <div className={styles.formRow}>
              <div className={styles.formGroup}>
                <label>Quantidade de Parcelas</label>
                <input
                  type="number"
                  min="1"
                  value={formData.parcelas_maximas}
                  onChange={(e) => setFormData({ ...formData, parcelas_maximas: parseInt(e.target.value) || 1 })}
                  placeholder="3"
                />
              </div>

              <div className={styles.formGroup}>
                <label>Preço no PIX (R$)</label>
                <input
                  type="number"
                  step="0.01"
                  min="0"
                  value={formData.preco_pix}
                  onChange={(e) => setFormData({ ...formData, preco_pix: parseFloat(e.target.value) })}
                  placeholder="0.00"
                />
              </div>

              <div className={styles.formGroup}>
                <label>Preço no Credito (R$)</label>
                <input
                  type="number"
                  step="0.01"
                  min="0"
                  value={formData.preco_credito}
                  onChange={(e) => handleCreditoChange(parseFloat(e.target.value))}
                  placeholder="0.00"
                />
              </div>

              <div className={styles.formGroup}>
                <label>Preço no Debito (R$)</label>
                <input
                  type="number"
                  step="0.01"
                  min="0"
                  value={formData.preco_debito}
                  onChange={(e) => setFormData({ ...formData, preco_debito: parseFloat(e.target.value) })}
                  placeholder="0.00"
                  disabled={usarMesmoValorPagamentos}
                />
              </div>

              <div className={styles.formGroup}>
                <label>Preço no Boleto (R$)</label>
                <input
                  type="number"
                  step="0.01"
                  min="0"
                  value={formData.preco_boleto}
                  onChange={(e) => setFormData({ ...formData, preco_boleto: parseFloat(e.target.value) })}
                  placeholder="0.00"
                  disabled={usarMesmoValorPagamentos}
                />
              </div>
            </div>

            <div className={styles.formGroup}>
              <label>Estoque *</label>
              <input
                type="number"
                min="0"
                value={formData.estoque}
                onChange={(e) => setFormData({ ...formData, estoque: parseInt(e.target.value) })}
                required
                placeholder="0"
              />
            </div>
          </div>

          <div className={styles.formCard}>
            <h2>Imagens</h2>

            <div className={styles.formGroup}>
              <label>Tipo de Imagem</label>
              <div className={styles.radioGroup}>
                <label className={styles.radioLabel}>
                  <input
                    type="radio"
                    value="url"
                    checked={imagemTipo === 'url'}
                    onChange={(e) => setImagemTipo('url')}
                  />
                  URL da Imagem
                </label>
                <label className={styles.radioLabel}>
                  <input
                    type="radio"
                    value="upload"
                    checked={imagemTipo === 'upload'}
                    onChange={(e) => setImagemTipo('upload')}
                  />
                  Upload de Arquivo
                </label>
              </div>
            </div>

            {imagemTipo === 'url' ? (
              <div className={styles.inputGroup}>
                <input
                  type="url"
                  value={imagemInput}
                  onChange={(e) => setImagemInput(e.target.value)}
                  placeholder="URL da imagem"
                  onKeyPress={(e) => e.key === 'Enter' && (e.preventDefault(), adicionarImagem())}
                />
                <button type="button" onClick={adicionarImagem} className={styles.btnAdd}>
                  Adicionar
                </button>
              </div>
            ) : (
              <div className={styles.uploadGroup}>
                <label htmlFor="upload-imagem-edit" className={styles.uploadLabel}>
                  {uploading ? 'Enviando...' : 'Escolher Arquivo'}
                </label>
                <input
                  type="file"
                  accept="image/*"
                  onChange={handleUploadImagem}
                  disabled={uploading}
                  id="upload-imagem-edit"
                  className={styles.uploadInput}
                />
                <small>Máximo 5MB (JPEG, PNG, GIF, WEBP)</small>
              </div>
            )}

            <div className={styles.tagsList}>
              {formData.imagens.map((img, index) => (
                <div key={index} className={styles.imagePreview}>
                  <img src={img} alt={`Imagem ${index + 1}`} />
                  <button type="button" onClick={() => removerImagem(index)}>×</button>
                </div>
              ))}
            </div>
          </div>

          <div className={styles.formCard}>
            <h2>Variações</h2>

            <div className={styles.formGroup}>
              <label>Cores Disponíveis</label>
              <div className={styles.inputGroup}>
                <input
                  type="text"
                  value={corInput}
                  onChange={(e) => setCorInput(e.target.value)}
                  placeholder="Ex: Preto, Branco, Azul"
                  onKeyPress={(e) => e.key === 'Enter' && (e.preventDefault(), adicionarCor())}
                />
                <button type="button" onClick={adicionarCor} className={styles.btnAdd}>
                  Adicionar
                </button>
              </div>
              <div className={styles.tagsList}>
                {formData.cores_disponiveis.map((cor, index) => (
                  <span key={index} className={styles.tag}>
                    {cor}
                    <button type="button" onClick={() => removerCor(index)}>×</button>
                  </span>
                ))}
              </div>
            </div>

            <div className={styles.formGroup}>
              <label>Tamanhos Disponíveis</label>
              <div className={styles.inputGroup}>
                <input
                  type="text"
                  value={tamanhoInput}
                  onChange={(e) => setTamanhoInput(e.target.value)}
                  placeholder="Ex: P, M, G, GG"
                  onKeyPress={(e) => e.key === 'Enter' && (e.preventDefault(), adicionarTamanho())}
                />
                <button type="button" onClick={adicionarTamanho} className={styles.btnAdd}>
                  Adicionar
                </button>
              </div>
              <div className={styles.tagsList}>
                {formData.tamanhos_disponiveis.map((tam, index) => (
                  <span key={index} className={styles.tag}>
                    {tam}
                    <button type="button" onClick={() => removerTamanho(index)}>×</button>
                  </span>
                ))}
              </div>
            </div>
          </div>

          <div className={styles.formCard}>
            <h2>Status</h2>

            <div className={styles.formGroup}>
              <label className={styles.checkboxLabel}>
                <input
                  type="checkbox"
                  checked={formData.ativo}
                  onChange={(e) => setFormData({ ...formData, ativo: e.target.checked })}
                />
                Produto ativo e visível na loja
              </label>
            </div>
          </div>

          <div className={styles.formActions}>
            <Link href="/admin/produtos" className={styles.btnCancel}>
              Cancelar
            </Link>
            <button type="submit" className={styles.btnSubmit} disabled={loading}>
              <FiSave />
              {loading ? 'Salvando...' : (isEditing ? 'Atualizar' : 'Criar') + ' Produto'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

/* eslint-disable @typescript-eslint/no-explicit-any */
'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useToast } from '@/contexts/ToastContext';
import { useRouter } from 'next/navigation';
import { productService, categoryService, tipoProdutoService } from '@/services/api';
import Link from 'next/link';
import { FiArrowLeft, FiSave } from 'react-icons/fi';
import styles from '../[id]/produto-form.module.scss';

const API_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000/api';

export default function NovoProdutoPage() {
  const { user, loading: authLoading } = useAuth();
  const { success, error: showError } = useToast();
  const router = useRouter();
  const [loading, setLoading] = useState(false);
  const [categorias, setCategorias] = useState<any[]>([]);
  const [tiposProduto, setTiposProduto] = useState<any[]>([]);
  const [uploading, setUploading] = useState(false);

  const [formData, setFormData] = useState({
    nome: '',
    descricao: '',
    preco: 0,
    preco_pix: 0,
    preco_debito: 0,
    preco_credito: 0,
    preco_boleto: 0,
    preco_original: 0,
    parcelas_maximas: 3,
    desconto_percentual: 0,
    categoria_id: '',
    categoria_ids: [] as string[],
    estoque: 0,
    imagens: [] as string[],
    cores_disponiveis: [] as string[],
    tamanhos_disponiveis: [] as string[],
    tipo_produto_id: null as number | null,
    ativo: true,
  });

  const [usarMesmoValorPagamentos, setUsarMesmoValorPagamentos] = useState(true);

  const [imagemInput, setImagemInput] = useState('');
  const [imagemTipo, setImagemTipo] = useState<'url' | 'upload'>('url');
  const [corInput, setCorInput] = useState('');
  const [tamanhoInput, setTamanhoInput] = useState('');

  useEffect(() => {
    if (!authLoading && (!user || !user.is_admin)) {
      router.push('/perfil');
    }
  }, [user, authLoading, router]);

  useEffect(() => {
    if (user && user.is_admin) {
      carregarCategorias();
      carregarTiposProduto();
    }
  }, [user]);

  const carregarCategorias = async () => {
    try {
      const response = await categoryService.getAllAdmin();
      if (response.success) {
        setCategorias(response.data || []);
      }
    } catch (error) {
      console.error('Erro ao carregar categorias:', error);
    }
  };

  const carregarTiposProduto = async () => {
    try {
      const response = await tipoProdutoService.getAll();
      if (response.success) {
        setTiposProduto(response.data || []);
      }
    } catch (error) {
      console.error('Erro ao carregar tipos de produto:', error);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.nome || !formData.preco || formData.categoria_ids.length === 0) {
      showError('Preencha os campos obrigatórios: Nome, Preço e Categoria');
      return;
    }

    setLoading(true);
    try {
      const categoriaIds = formData.categoria_ids.map((id) => parseInt(id, 10)).filter((id) => !Number.isNaN(id));
      const data = {
        ...formData,
        categoria_id: categoriaIds[0] || parseInt(formData.categoria_id, 10),
        categoria_ids: categoriaIds,
        preco: parseFloat(formData.preco.toString()),
        preco_pix: formData.preco_pix > 0 ? parseFloat(formData.preco_pix.toString()) : parseFloat(formData.preco.toString()),
        preco_debito: formData.preco_debito > 0 ? parseFloat(formData.preco_debito.toString()) : parseFloat(formData.preco.toString()),
        preco_credito: formData.preco_credito > 0 ? parseFloat(formData.preco_credito.toString()) : parseFloat(formData.preco.toString()),
        preco_boleto: formData.preco_boleto > 0 ? parseFloat(formData.preco_boleto.toString()) : parseFloat(formData.preco.toString()),
        preco_original: parseFloat(formData.preco_original.toString()) || null,
        parcelas_maximas: parseInt(formData.parcelas_maximas.toString(), 10) || 3,
        desconto_percentual: parseFloat(formData.desconto_percentual.toString()) || 0,
        estoque: parseInt(formData.estoque.toString()),
      };

      const response = await productService.create(data);
      if (response.success) {
        success('Produto criado com sucesso!');
        router.push('/admin/produtos');
      }
    } catch (error: any) {
      showError(error.message || 'Erro ao salvar produto');
    } finally {
      setLoading(false);
    }
  };

  const adicionarImagem = () => {
    if (imagemInput.trim()) {
      setFormData({
        ...formData,
        imagens: [...formData.imagens, imagemInput.trim()],
      });
      setImagemInput('');
    }
  };

  const handleUploadImagem = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Validar tipo de arquivo
    const allowedTypes = ['image/jpeg', 'image/jpg', 'image/png', 'image/gif', 'image/webp'];
    if (!allowedTypes.includes(file.type)) {
      showError('Tipo de arquivo não suportado. Use apenas imagens (JPEG, PNG, GIF, WEBP).');
      return;
    }

    // Validar tamanho (5MB)
    if (file.size > 5 * 1024 * 1024) {
      showError('Arquivo muito grande. O tamanho máximo é 5MB.');
      return;
    }

    setUploading(true);
    try {
      const formDataUpload = new FormData();
      formDataUpload.append('imagem', file);

      const token = localStorage.getItem('token');
      const response = await fetch(`${API_URL}/produtos/upload-imagem`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
        },
        body: formDataUpload,
      });

      const data = await response.json();

      if (data.success && data.data.url) {
        // Adicionar a URL da imagem ao array de imagens
        const imageUrl = data.data.url.startsWith('http') 
          ? data.data.url 
          : `${API_URL.replace('/api', '')}${data.data.url}`;

        setFormData(prev => ({
          ...prev,
          imagens: [...prev.imagens, imageUrl],
        }));
        success('Imagem enviada com sucesso!');
      } else {
        showError(data.message || 'Erro ao fazer upload da imagem');
      }
    } catch (error: any) {
      console.error('Erro ao fazer upload:', error);
      showError('Erro ao fazer upload da imagem');
    } finally {
      setUploading(false);
      // Limpar o input file
      e.target.value = '';
    }
  };

  const removerImagem = (index: number) => {
    setFormData({
      ...formData,
      imagens: formData.imagens.filter((_, i) => i !== index),
    });
  };

  const adicionarCor = () => {
    if (corInput.trim() && !formData.cores_disponiveis.includes(corInput.trim())) {
      setFormData({
        ...formData,
        cores_disponiveis: [...formData.cores_disponiveis, corInput.trim()],
      });
      setCorInput('');
    }
  };

  const removerCor = (index: number) => {
    setFormData({
      ...formData,
      cores_disponiveis: formData.cores_disponiveis.filter((_, i) => i !== index),
    });
  };

  const adicionarTamanho = () => {
    if (tamanhoInput.trim() && !formData.tamanhos_disponiveis.includes(tamanhoInput.trim())) {
      setFormData({
        ...formData,
        tamanhos_disponiveis: [...formData.tamanhos_disponiveis, tamanhoInput.trim()],
      });
      setTamanhoInput('');
    }
  };

  const removerTamanho = (index: number) => {
    setFormData({
      ...formData,
      tamanhos_disponiveis: formData.tamanhos_disponiveis.filter((_, i) => i !== index),
    });
  };

  const handleCreditoChange = (valor: number) => {
    if (usarMesmoValorPagamentos) {
      setFormData(prev => ({
        ...prev,
        preco_credito: valor,
        preco_debito: valor,
        preco_boleto: valor,
      }));
      return;
    }

    setFormData(prev => ({
      ...prev,
      preco_credito: valor,
    }));
  };

  const handleToggleMesmoValor = (checked: boolean) => {
    setUsarMesmoValorPagamentos(checked);
    if (checked) {
      setFormData(prev => ({
        ...prev,
        preco_debito: prev.preco_credito || prev.preco,
        preco_boleto: prev.preco_credito || prev.preco,
      }));
    }
  };

  // Calcular desconto automaticamente
  useEffect(() => {
    if (formData.preco_original > 0 && formData.preco > 0) {
      const desconto = ((formData.preco_original - formData.preco) / formData.preco_original) * 100;
      setFormData(prev => ({ ...prev, desconto_percentual: Math.round(desconto * 100) / 100 }));
    }
  }, [formData.preco, formData.preco_original]);

  if (authLoading) {
    return (
      <div className={styles.loading}>
        <div className="spinner-border" role="status"></div>
      </div>
    );
  }

  if (!user || !user.is_admin) {
    return null;
  }

  return (
    <div className={styles.produtoForm}>
      <div className={styles.container}>
        <div className={styles.header}>
          <Link href="/admin/produtos" className={styles.backButton}>
            <FiArrowLeft /> Voltar para Produtos
          </Link>
          <h1>Novo Produto</h1>
        </div>

        <form onSubmit={handleSubmit} className={styles.form}>
          <div className={styles.formCard}>
            <h2>Informações Básicas</h2>

            <div className={styles.formGroup}>
              <label>Nome do Produto *</label>
              <input
                type="text"
                name="nome"
                value={formData.nome}
                onChange={(e) => setFormData({ ...formData, nome: e.target.value })}
                required
                placeholder="Ex: Camiseta Básica"
              />
            </div>

            <div className={styles.formGroup}>
              <label>Descrição</label>
              <textarea
                name="descricao"
                value={formData.descricao}
                onChange={(e) => setFormData({ ...formData, descricao: e.target.value })}
                placeholder="Descreva o produto..."
                rows={5}
              />
            </div>

            <div className={styles.formGroup}>
              <label>Categorias *</label>
              <select
                multiple
                name="categoria_ids"
                value={formData.categoria_ids}
                onChange={(e) => {
                  const selected = Array.from(e.target.selectedOptions).map((opt) => opt.value);
                  setFormData({
                    ...formData,
                    categoria_ids: selected,
                    categoria_id: selected[0] || '',
                  });
                }}
                required
              >
                {categorias.map((cat) => (
                  <option key={cat.id} value={cat.id}>
                    {cat.nome}
                  </option>
                ))}
              </select>
              <small>Segure Ctrl (Windows) para selecionar mais de uma.</small>
            </div>

            <div className={styles.formGroup}>
              <label>Tipo de Produto (Configuração de Frete)</label>
              <select
                value={formData.tipo_produto_id || ''}
                onChange={(e) => setFormData({
                  ...formData,
                  tipo_produto_id: e.target.value ? parseInt(e.target.value) : null
                })}
              >
                <option value="">Usar configuração padrão (Fallback)</option>
                {tiposProduto.map((tipo) => (
                  <option key={tipo.id} value={tipo.id}>
                    {tipo.nome} ({tipo.codigo})
                  </option>
                ))}
              </select>
              <small>Define como o produto será empacotado para cálculo de frete</small>
            </div>
          </div>

          <div className={styles.formCard}>
            <h2>Preços e Promoção</h2>

            <div className={styles.formRow}>
              <div className={styles.formGroup}>
                <label>Preço Atual (R$) *</label>
                <input
                  type="number"
                  name="preco"
                  step="0.01"
                  min="0"
                  value={formData.preco}
                  onChange={(e) => setFormData({ ...formData, preco: parseFloat(e.target.value) })}
                  required
                  placeholder="0.00"
                />
              </div>

              <div className={styles.formGroup}>
                <label>Preço Original (R$)</label>
                <input
                  type="number"
                  step="0.01"
                  min="0"
                  value={formData.preco_original || ''}
                  onChange={(e) => setFormData({ ...formData, preco_original: parseFloat(e.target.value) || 0 })}
                  placeholder="0.00"
