            <button type="submit" className={styles.btnSubmit} disabled={loading}>
              <FiSave /> {loading ? 'Salvando...' : 'Criar Produto'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

/* eslint-disable @typescript-eslint/no-explicit-any */
'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useRouter } from 'next/navigation';
import { productService, categoryService } from '@/services/api';
import { Product } from '@/types';
import Link from 'next/link';
import { Plus, Edit, Trash2, Eye, Package, ArrowLeft } from 'lucide-react';
import { toast } from 'sonner';
import styles from './produtos.module.scss';

export default function AdminProdutosPage() {
  const { user, loading: authLoading } = useAuth();
  const router = useRouter();
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);
  const [busca, setBusca] = useState('');
  const [categoriaFiltro, setCategoriaFiltro] = useState('');
  const [categorias, setCategorias] = useState<any[]>([]);
  const [mostrarInativos, setMostrarInativos] = useState(false);

  useEffect(() => {
    if (!authLoading && (!user || !user.is_admin)) {
      router.push('/perfil');
    }
  }, [user, authLoading, router]);

  useEffect(() => {
    if (user && user.is_admin) {
      carregarDados();
    }
  }, [user]);

  const carregarDados = async () => {
    setLoading(true);
    try {
      const [produtosRes, categoriasRes] = await Promise.all([
        productService.getAllAdmin({ limite: 10000 }),
        categoryService.getAllAdmin(),
      ]);

      if (produtosRes.success) {
        setProducts(produtosRes.data || []);
      }

      if (categoriasRes.success) {
        setCategorias(categoriasRes.data || []);
      }
    } catch (error) {
      console.error('Erro ao carregar dados:', error);
      toast.error('Erro ao carregar produtos');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id: number) => {
    if (!confirm('Tem certeza que deseja excluir este produto?')) {
      return;
    }

    try {
      const response = await productService.delete(id);
      if (response.success) {
        toast.success('✨ Produto excluído com sucesso!');
        setProducts((prev) => prev.map((produto) => (produto.id === id ? { ...produto, ativo: false } : produto)));
        carregarDados();
      }
    } catch (error: any) {
      toast.error(error.message || 'Erro ao excluir produto');
    }
  };

  const produtosFiltrados = products.filter((p) => {
    const matchBusca = !busca || p.nome.toLowerCase().includes(busca.toLowerCase());
    const categoriaId = parseInt(categoriaFiltro, 10);
    const matchCategoria = !categoriaFiltro
      || (Array.isArray(p.categoria_ids) && p.categoria_ids.includes(categoriaId))
      || p.categoria_id?.toString() === categoriaFiltro;
    const matchAtivo = mostrarInativos ? true : p.ativo;
    return matchBusca && matchCategoria && matchAtivo;
  });

  if (authLoading || loading) {
    return (
      <div className={styles.loading}>
        <div className="spinner-border" role="status"></div>
      </div>
    );
  }

  if (!user || !user.is_admin) {
    return null;
  }

  return (
    <div className={styles.adminProdutos}>
      <div className={styles.container}>
        <div className={styles.header}>
          <div className={styles.headerLeft}>
            <Link href="/admin" className={styles.backButton}>
              <ArrowLeft size={20} /> Voltar
            </Link>
            <h1>Gerenciar Produtos</h1>
          </div>
          <Link href="/admin/produtos/novo" className={styles.addButton} data-testid="btn-add-product">
            <Plus size={20} /> Novo Produto
          </Link>
        </div>

        <div className={styles.filters}>
          <input
            type="text"
            placeholder="Buscar produtos..."
            value={busca}
            onChange={(e) => setBusca(e.target.value)}
            className={styles.searchInput}
          />
          <select
            value={categoriaFiltro}
            onChange={(e) => setCategoriaFiltro(e.target.value)}
            className={styles.filterSelect}
          >
            <option value="">Todas as categorias</option>
            {categorias.map((cat) => (
              <option key={cat.id} value={cat.id}>
                {cat.nome}
              </option>
            ))}
          </select>
          <label className={styles.filterToggle}>
            <input
              type="checkbox"
              checked={mostrarInativos}
              onChange={(e) => setMostrarInativos(e.target.checked)}
            />
            Mostrar inativos
          </label>
        </div>

        <div className={styles.stats}>
          <div className={styles.statCard}>
            <Package size={24} />
            <div>
              <p>Total de Produtos</p>
              <h3>{mostrarInativos ? products.length : products.filter((p) => p.ativo).length}</h3>
            </div>
          </div>
          <div className={styles.statCard}>
            <Eye size={24} />
            <div>
              <p>Produtos Ativos</p>
              <h3>{products.filter((p) => p.ativo).length}</h3>
            </div>
          </div>
        </div>

        <div className={styles.tableContainer}>
          <table className={styles.table} data-testid="products-table">
            <thead>
              <tr>
                <th>ID</th>
                <th>Produto</th>
                <th>Categoria</th>
                <th>Preço</th>
                <th>Parcelas</th>
                <th>Estoque</th>
                <th>Status</th>
                <th>Ações</th>
              </tr>
            </thead>
            <tbody>
              {produtosFiltrados.map((produto) => (
                <tr key={produto.id}>
                  <td>#{produto.id}</td>
                  <td>
                    <div className={styles.productInfo}>
                      {(() => {
                        const imageUrl = Array.isArray(produto.imagens)
                          ? produto.imagens[0]
                          : produto.imagens;

                        return imageUrl ? (
                          <img src={imageUrl} alt={produto.nome} />
                        ) : null;
                      })()}
                      <span>{produto.nome}</span>
                    </div>
                  </td>
                  <td>{Array.isArray(produto.categoria_nomes) ? produto.categoria_nomes[0] : produto.categoria_nome || '-'}</td>
                  <td>R$ {Number(produto.preco || 0).toFixed(2)}</td>
                  <td>{produto.parcelas_maximas ? `${produto.parcelas_maximas}x` : '3x'}</td>
                  <td>
                    <span
                      className={`${styles.badge} ${
                        produto.estoque === 0 ? styles.badgeDanger : styles.badgeSuccess
                      }`}
                    >
                      {produto.estoque} un.
                    </span>
                  </td>
                  <td>
                    <span
                      className={`${styles.badge} ${
                        produto.ativo ? styles.badgeSuccess : styles.badgeSecondary
                      }`}
                    >
                      {produto.ativo ? 'Ativo' : 'Inativo'}
                    </span>
                  </td>
                  <td>
                    <div className={styles.actions}>
                      <Link
                        href={`/produtos/${produto.id}`}
                        className={styles.btnView}
                        title="Ver"
                        data-testid="btn-view"
                        aria-label="Ver produto"
                      >
                        <Eye size={18} />
                      </Link>
                      <Link
                        href={`/admin/produtos/${produto.id}`}
                        className={styles.btnEdit}
                        title="Editar"
                        data-testid="btn-edit"
                        aria-label="Editar produto"
                      >
                        <Edit size={18} />
                      </Link>
                      <button
                        onClick={() => handleDelete(produto.id)}
                        className={styles.btnDelete}
                        title="Excluir"
                        data-testid="btn-delete"
                        aria-label="Excluir produto"
                      >
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          {produtosFiltrados.length === 0 && (
            <div className={styles.empty}>
              <p>Nenhum produto encontrado</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

/* eslint-disable @typescript-eslint/no-explicit-any */
'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useToast } from '@/contexts/ToastContext';
import { useRouter } from 'next/navigation';
import { promocaoService, productService } from '@/services/api';
import Link from 'next/link';
import { FiArrowLeft, FiPlus, FiEdit, FiTrash2, FiPercent, FiCalendar, FiToggleLeft, FiToggleRight, FiX } from 'react-icons/fi';
import styles from './promocoes.module.scss';

interface Promocao {
  id: number;
  nome: string;
  descricao?: string;
  tipo_desconto: 'percentual' | 'valor_fixo';
  desconto_percentual?: number;
  desconto_valor?: number;
  data_inicio: string;
  data_fim: string;
  produtos_aplicaveis?: number[];
  ativa: boolean;
  data_criacao: string;
}

interface Produto {
  id: number;
  nome: string;
  preco: number;
}

export default function AdminPromocoesPage() {
  const { user, loading: authLoading } = useAuth();
  const { showToast } = useToast();
  const router = useRouter();

  const [promocoes, setPromocoes] = useState<Promocao[]>([]);
  const [produtos, setProdutos] = useState<Produto[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editingPromocao, setEditingPromocao] = useState<Promocao | null>(null);
  const [selectedProdutos, setSelectedProdutos] = useState<number[]>([]);
  const [searchProduto, setSearchProduto] = useState('');

  const [formData, setFormData] = useState({
    nome: '',
    descricao: '',
    tipo_desconto: 'percentual' as 'percentual' | 'valor_fixo',
    desconto_percentual: 0,
    desconto_valor: 0,
    data_inicio: '',
    data_fim: '',
    produtos_aplicaveis: [] as number[],
    ativa: true,
  });

  useEffect(() => {
    if (!authLoading && (!user || !user.is_admin)) {
      router.push('/perfil');
    }
  }, [user, authLoading, router]);

  useEffect(() => {
    if (user && user.is_admin) {
      carregarPromocoes();
      carregarProdutos();
    }
  }, [user]);

  const carregarPromocoes = async () => {
    setLoading(true);
    try {
      const response = await promocaoService.getAll();
      if (response.success) {
        setPromocoes(response.data || []);
      }
    } catch (error) {
      console.error('Erro ao carregar promoções:', error);
      showToast('Erro ao carregar promoções', 'error');
    } finally {
      setLoading(false);
    }
  };

  const carregarProdutos = async () => {
    try {
      const response = await productService.getAllAdmin({ limite: 1000 });
      if (response.success) {
        setProdutos(response.data || []);
      }
    } catch (error) {
      console.error('Erro ao carregar produtos:', error);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.nome.trim()) {
      showToast('Nome da promoção é obrigatório', 'error');
      return;
    }

    if (!formData.data_inicio || !formData.data_fim) {
      showToast('Datas de início e fim são obrigatórias', 'error');
      return;
    }

    if (new Date(formData.data_inicio) >= new Date(formData.data_fim)) {
      showToast('Data de fim deve ser posterior à data de início', 'error');
      return;
    }

    const dadosPromocao = {
      ...formData,
      produtos_aplicaveis: selectedProdutos.length > 0 ? selectedProdutos : undefined,
    };

    try {
      if (editingPromocao) {
        const response = await promocaoService.update(editingPromocao.id, dadosPromocao);
        if (response.success) {
          showToast('Promoção atualizada com sucesso!', 'success');
        }
      } else {
        const response = await promocaoService.create(dadosPromocao);
        if (response.success) {
          showToast('Promoção criada com sucesso!', 'success');
        }
      }

      setShowModal(false);
      resetForm();
      carregarPromocoes();
    } catch (error: any) {
      showToast(error.message || 'Erro ao salvar promoção', 'error');
    }
  };

  const handleEdit = (promocao: Promocao) => {
    setEditingPromocao(promocao);
    setFormData({
      nome: promocao.nome,
      descricao: promocao.descricao || '',
      tipo_desconto: promocao.tipo_desconto,
      desconto_percentual: promocao.desconto_percentual || 0,
      desconto_valor: promocao.desconto_valor || 0,
      data_inicio: promocao.data_inicio.split('T')[0],
      data_fim: promocao.data_fim.split('T')[0],
      produtos_aplicaveis: promocao.produtos_aplicaveis || [],
      ativa: promocao.ativa,
    });
    setSelectedProdutos(promocao.produtos_aplicaveis || []);
    setShowModal(true);
  };

  const handleDelete = async (id: number) => {
    if (!confirm('Tem certeza que deseja excluir esta promoção?')) {
      return;
    }

    try {
      const response = await promocaoService.delete(id);
      if (response.success) {
        showToast('Promoção excluída com sucesso!', 'success');
        carregarPromocoes();
      }
    } catch (error: any) {
      showToast(error.message || 'Erro ao excluir promoção', 'error');
    }
  };

  const handleToggleAtiva = async (id: number, ativaAtual: boolean) => {
    try {
      const response = await promocaoService.toggle(id);
      if (response.success) {
        showToast(
          `Promoção ${!ativaAtual ? 'ativada' : 'desativada'} com sucesso!`,
          'success'
        );
        carregarPromocoes();
      }
    } catch (error: any) {
      showToast(error.message || 'Erro ao alterar status', 'error');
    }
  };

  const handleToggleProduto = (produtoId: number) => {
    setSelectedProdutos(prev => 
      prev.includes(produtoId)
        ? prev.filter(id => id !== produtoId)
        : [...prev, produtoId]
    );
  };

  const resetForm = () => {
    setFormData({
      nome: '',
      descricao: '',
      tipo_desconto: 'percentual',
      desconto_percentual: 0,
      desconto_valor: 0,
      data_inicio: '',
      data_fim: '',
      produtos_aplicaveis: [],
      ativa: true,
    });
    setSelectedProdutos([]);
    setEditingPromocao(null);
    setSearchProduto('');
  };

  const handleOpenModal = () => {
    resetForm();
    // Data padrão: hoje até daqui 7 dias
    const hoje = new Date().toISOString().split('T')[0];
    const daquiSete = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
    setFormData(prev => ({
      ...prev,
      data_inicio: hoje,
      data_fim: daquiSete,
    }));
    setShowModal(true);
  };

  const getStatusPromocao = (promocao: Promocao) => {
    if (!promocao.ativa) return { label: 'Inativa', class: 'inativa' };

    const agora = new Date();
    const inicio = new Date(promocao.data_inicio);
    const fim = new Date(promocao.data_fim);

    if (agora < inicio) return { label: 'Agendada', class: 'agendada' };
    if (agora > fim) return { label: 'Expirada', class: 'expirada' };
    return { label: 'Vigente', class: 'vigente' };
  };

  if (authLoading || !user || !user.is_admin) {
    return null;
  }

  return (
    <div className={styles.adminPromocoesPage}>
      <div className="container">
        {/* Header */}
        <div className={styles.header}>
          <div>
            <Link href="/admin" className={styles.backButton}>
              <FiArrowLeft /> Voltar
            </Link>
            <h1><FiPercent /> Gerenciar Promoções</h1>
            <p>Crie campanhas promocionais com desconto para seus produtos</p>
          </div>
          <button className={styles.addButton} onClick={handleOpenModal}>
            <FiPlus /> Nova Promoção
          </button>
        </div>

        {/* Lista de Promoções */}
        {loading ? (
          <div className={styles.loading}>Carregando promoções...</div>
        ) : promocoes.length === 0 ? (
          <div className={styles.empty}>
            <FiPercent size={48} />
            <h2>Nenhuma promoção cadastrada</h2>
            <p>Comece criando sua primeira campanha promocional</p>
            <button onClick={handleOpenModal}>
