'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';
import Image from 'next/image';
import Breadcrumbs from '@/components/Breadcrumbs/Breadcrumbs';
import { Heart, ShoppingCart, Trash2, AlertCircle } from 'lucide-react';
import { useNotification } from '@/hooks/useNotification';
import { confirmDelete } from '@/utils/alerts';
import styles from './favoritos.module.scss';

interface Produto {
  id: number;
  nome: string;
  slug: string;
  preco: number;
  preco_promocional?: number;
  imagem_principal: string;
  estoque: number;
}

export default function FavoritosPage() {
  const [favoritos, setFavoritos] = useState<Produto[]>([]);
  const [loading, setLoading] = useState(true);
  const { success, error, warning } = useNotification();

  useEffect(() => {
    carregarFavoritos();
  }, []);

  const carregarFavoritos = async () => {
    try {
      // Verificar se o usuário está autenticado
      const token = localStorage.getItem('token');

      if (!token) {
        // Carregar favoritos do localStorage para usuários não autenticados
        const favoritosLocal = JSON.parse(localStorage.getItem('favoritos') || '[]');
        if (favoritosLocal.length > 0) {
          // Buscar detalhes dos produtos
          const produtosPromises = favoritosLocal.map((id: number) =>
            fetch(`${process.env.NEXT_PUBLIC_API_URL}/produtos/${id}`).then(r => r.json())
          );
          const produtos = await Promise.all(produtosPromises);
          setFavoritos(produtos.filter(p => p));
        }
        setLoading(false);
        return;
      }

      // Buscar favoritos do backend para usuários autenticados
      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/favoritos`, {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });

      if (response.ok) {
        const data = await response.json();
        setFavoritos(data);
      }
    } catch (error) {
      console.error('Erro ao carregar favoritos:', error);
    } finally {
      setLoading(false);
    }
  };

  const removerFavorito = async (produtoId: number) => {
    const shouldDelete = await confirmDelete(
      'Remover dos Favoritos?',
      'Este produto será removido da sua lista de desejos'
    );

    if (!shouldDelete) return;

    try {
      const token = localStorage.getItem('token');

      if (!token) {
        // Remover do localStorage
        const favoritosLocal = JSON.parse(localStorage.getItem('favoritos') || '[]');
        const novosFavoritos = favoritosLocal.filter((id: number) => id !== produtoId);
        localStorage.setItem('favoritos', JSON.stringify(novosFavoritos));
        setFavoritos(favoritos.filter(p => p.id !== produtoId));
        success('Produto removido dos favoritos!');
        return;
      }

      // Remover do backend
      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/favoritos/${produtoId}`, {
        method: 'DELETE',
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });

      if (response.ok) {
        setFavoritos(favoritos.filter(p => p.id !== produtoId));
        success('Produto removido dos favoritos!');
      } else {
        error('Erro ao remover produto');
      }
    } catch (err) {
      error('Erro ao remover produto');
      console.error('Erro ao remover favorito:', err);
    }
  };

  const adicionarAoCarrinho = (produto: Produto) => {
    const carrinho = JSON.parse(localStorage.getItem('carrinho') || '[]');
    const itemExistente = carrinho.find((item: any) => item.produto_id === produto.id);

    if (itemExistente) {
      itemExistente.quantidade += 1;
    } else {
      carrinho.push({
        produto_id: produto.id,
        nome: produto.nome,
        preco: produto.preco_promocional || produto.preco,
        quantidade: 1,
        imagem: produto.imagem_principal
      });
    }

    localStorage.setItem('carrinho', JSON.stringify(carrinho));
    window.dispatchEvent(new Event('carrinhoAtualizado'));

    success('Produto adicionado ao carrinho!');
  };

  const formatarPreco = (preco: number) => {
    return preco.toLocaleString('pt-BR', {
      style: 'currency',
      currency: 'BRL'
    });
  };

  if (loading) {
    return (
      <div className={styles.page}>
        <div className="container">
          <Breadcrumbs items={[{ label: 'Meus Favoritos' }]} />
          <div className={styles.loading}>
            <p>Carregando favoritos...</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className={styles.page}>
      <div className="container">
        <Breadcrumbs items={[{ label: 'Meus Favoritos' }]} />

        <div className={styles.header}>
          <Heart className={styles.headerIcon} />
          <h1>Meus Favoritos</h1>
          <p>
            {favoritos.length > 0
              ? `Você tem ${favoritos.length} ${favoritos.length === 1 ? 'produto' : 'produtos'} na sua lista de desejos`
              : 'Sua lista de desejos está vazia'}
          </p>
        </div>

        {favoritos.length === 0 ? (
          <div className={styles.empty}>
            <Heart className={styles.emptyIcon} />
            <h2>Nenhum produto favorito ainda</h2>
            <p>
              Comece a adicionar produtos aos seus favoritos clicando no ícone de coração 
              nas páginas de produtos
            </p>
            <Link href="/produtos" className={styles.btnExplorar}>
              Explorar Produtos
            </Link>
          </div>
        ) : (
          <>
            <div className={styles.grid}>
              {favoritos.map((produto) => (
                <div key={produto.id} className={styles.card}>
                  <button
                    className={styles.btnRemover}
                    onClick={() => removerFavorito(produto.id)}
                    title="Remover dos favoritos"
                  >
                    <Trash2 size={18} />
                  </button>

                  {produto.preco_promocional && (
                    <div className={styles.badge}>OFERTA</div>
                  )}

                  {produto.estoque === 0 && (
                    <div className={styles.badgeIndisponivel}>Esgotado</div>
                  )}

                  <Link href={`/produto/${produto.slug}`} className={styles.imageLink}>
                    <div className={styles.imageWrapper}>
                      {produto.imagem_principal ? (
                        <Image
                          src={produto.imagem_principal}
                          alt={produto.nome}
                          fill
                          sizes="(max-width: 768px) 100vw, (max-width: 1200px) 50vw, 33vw"
                          className={styles.image}
                        />
                      ) : null}
                    </div>
                  </Link>

                  <div className={styles.cardContent}>
                    <Link href={`/produto/${produto.slug}`}>
                      <h3 className={styles.nome}>{produto.nome}</h3>
                    </Link>

                    <div className={styles.priceSection}>
                      {produto.preco_promocional ? (
                        <>
                          <span className={styles.precoOriginal}>
                            {formatarPreco(produto.preco)}
                          </span>
                          <span className={styles.precoPromocional}>
                            {formatarPreco(produto.preco_promocional)}
                          </span>
                          <span className={styles.desconto}>
                            {Math.round(((produto.preco - produto.preco_promocional) / produto.preco) * 100)}% OFF
                          </span>
                        </>
                      ) : (
                        <span className={styles.preco}>
                          {formatarPreco(produto.preco)}
                        </span>
                      )}
                    </div>

                    <button
                      className={styles.btnCarrinho}
                      onClick={() => adicionarAoCarrinho(produto)}
                      disabled={produto.estoque === 0}
                    >
                      <ShoppingCart size={18} />
                      {produto.estoque === 0 ? 'Esgotado' : 'Adicionar ao Carrinho'}
                    </button>
                  </div>
                </div>
              ))}
            </div>

            <div className={styles.actions}>
              <Link href="/produtos" className={styles.btnContinuar}>
                Continuar Comprando
              </Link>
            </div>
          </>
        )}

        <div className={styles.infoSection}>
          <h2>Sobre os Favoritos</h2>

          <div className={styles.infoGrid}>
            <div className={styles.infoCard}>
              <Heart className={styles.infoIcon} />
              <h3>Salve o que você ama</h3>
              <p>
                Adicione produtos à sua lista de favoritos para encontrá-los facilmente depois
              </p>
            </div>

            <div className={styles.infoCard}>
              <AlertCircle className={styles.infoIcon} />
              <h3>Não perca promoções</h3>
              <p>
                Acompanhe seus produtos favoritos e seja notificado sobre descontos especiais
              </p>
            </div>

            <div className={styles.infoCard}>
              <ShoppingCart className={styles.infoIcon} />
              <h3>Compre quando quiser</h3>
              <p>
                Seus favoritos ficam salvos para você comprar no momento certo
              </p>
            </div>
          </div>

          <div className={styles.tips}>
            <h3>Dicas</h3>
            <ul>
              <li>Favoritos são salvos automaticamente enquanto você navega</li>
              <li>Faça login para sincronizar favoritos entre dispositivos</li>
              <li>Use favoritos para criar listas de presentes</li>
              <li>Compartilhe produtos favoritos com amigos e família</li>
            </ul>
          </div>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect, Suspense } from 'react';
import { useSearchParams, useRouter } from 'next/navigation';
import Link from 'next/link';
import { FiLock, FiCheckCircle, FiAlertCircle, FiEye, FiEyeOff } from 'react-icons/fi';
import Breadcrumbs from '@/components/Breadcrumbs/Breadcrumbs';
import styles from './nova-senha.module.scss';

function NovaSenhaContent() {
  const searchParams = useSearchParams();
  const router = useRouter();
  const [token, setToken] = useState('');
  const [novaSenha, setNovaSenha] = useState('');
  const [confirmarSenha, setConfirmarSenha] = useState('');
  const [mostrarSenha, setMostrarSenha] = useState(false);
  const [mostrarConfirmar, setMostrarConfirmar] = useState(false);
  const [loading, setLoading] = useState(false);
  const [erro, setErro] = useState('');
  const [sucesso, setSucesso] = useState(false);

  useEffect(() => {
    const tokenParam = searchParams.get('token');
    if (tokenParam) {
      setToken(tokenParam);
    } else {
      setErro('Token não encontrado');
    }
  }, [searchParams]);

  const validarSenha = (senha: string): string[] => {
    const erros = [];
    if (senha.length < 8) erros.push('Mínimo de 8 caracteres');
    if (!/[A-Z]/.test(senha)) erros.push('Uma letra maiúscula');
    if (!/[a-z]/.test(senha)) erros.push('Uma letra minúscula');
    if (!/[0-9]/.test(senha)) erros.push('Um número');
    if (!/[!@#$%^&*(),.?":{}|<>]/.test(senha)) erros.push('Um caractere especial');
    return erros;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setErro('');

    if (!token) {
      setErro('Token inválido');
      return;
    }

    if (!novaSenha || !confirmarSenha) {
      setErro('Preencha todos os campos');
      return;
    }

    const errosValidacao = validarSenha(novaSenha);
    if (errosValidacao.length > 0) {
      setErro(`Senha deve conter: ${errosValidacao.join(', ')}`);
      return;
    }

    if (novaSenha !== confirmarSenha) {
      setErro('As senhas não coincidem');
      return;
    }

    setLoading(true);

    try {
      const apiUrl = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000/api';
      const response = await fetch(`${apiUrl}/auth/redefinir-senha`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          token,
          novaSenha,
        }),
      });

      const data = await response.json();

      if (data.success) {
        setSucesso(true);
        setTimeout(() => {
          router.push('/perfil');
        }, 3000);
      } else {
        setErro(data.error || 'Erro ao redefinir senha');
      }
    } catch (error) {
      setErro('Erro ao conectar com o servidor');
    } finally {
      setLoading(false);
    }
  };

  if (sucesso) {
    return (
      <div className={styles.container}>
        <Breadcrumbs
          items={[
            { label: 'Início', href: '/' },
            { label: 'Nova Senha', href: '/nova-senha' },
          ]}
        />

        <div className={styles.content}>
          <div className={styles.sucessoCard}>
            <FiCheckCircle className={styles.sucessoIcon} />
            <h1>Senha Redefinida!</h1>
            <p>Sua senha foi alterada com sucesso.</p>
            <p>Redirecionando para a sua conta...</p>
            <Link href="/perfil" className={styles.loginLink}>
              Ir para Minha Conta
            </Link>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className={styles.container}>
      <Breadcrumbs
        items={[
          { label: 'Início', href: '/' },
          { label: 'Nova Senha', href: '/nova-senha' },
        ]}
      />

      <div className={styles.content}>
        <div className={styles.card}>
          <div className={styles.header}>
            <FiLock className={styles.icon} />
            <h1>Redefinir Senha</h1>
            <p>Digite sua nova senha abaixo</p>
          </div>

          <form onSubmit={handleSubmit} className={styles.form}>
            <div className={styles.formGroup}>
              <label htmlFor="novaSenha">Nova Senha</label>
              <div className={styles.inputWrapper}>
                <input
                  type={mostrarSenha ? 'text' : 'password'}
                  id="novaSenha"
                  value={novaSenha}
                  onChange={(e) => setNovaSenha(e.target.value)}
                  placeholder="Digite sua nova senha"
                  required
                  disabled={loading || !token}
                />
                <button
                  type="button"
                  className={styles.togglePassword}
                  onClick={() => setMostrarSenha(!mostrarSenha)}
                  aria-label={mostrarSenha ? 'Ocultar senha' : 'Mostrar senha'}
                >
                  {mostrarSenha ? <FiEyeOff /> : <FiEye />}
                </button>
              </div>
            </div>

            <div className={styles.formGroup}>
              <label htmlFor="confirmarSenha">Confirmar Senha</label>
              <div className={styles.inputWrapper}>
                <input
                  type={mostrarConfirmar ? 'text' : 'password'}
                  id="confirmarSenha"
                  value={confirmarSenha}
                  onChange={(e) => setConfirmarSenha(e.target.value)}
                  placeholder="Digite novamente sua nova senha"
                  required
                  disabled={loading || !token}
                />
                <button
                  type="button"
                  className={styles.togglePassword}
                  onClick={() => setMostrarConfirmar(!mostrarConfirmar)}
                  aria-label={mostrarConfirmar ? 'Ocultar senha' : 'Mostrar senha'}
                >
                  {mostrarConfirmar ? <FiEyeOff /> : <FiEye />}
                </button>
              </div>
            </div>

            <div className={styles.requisitos}>
              <p>A senha deve conter:</p>
              <ul>
                <li className={novaSenha.length >= 8 ? styles.valido : ''}>
                  Mínimo de 8 caracteres
                </li>
                <li className={/[A-Z]/.test(novaSenha) ? styles.valido : ''}>
                  Uma letra maiúscula
                </li>
                <li className={/[a-z]/.test(novaSenha) ? styles.valido : ''}>
                  Uma letra minúscula
                </li>
                <li className={/[0-9]/.test(novaSenha) ? styles.valido : ''}>
                  Um número
                </li>
                <li className={/[!@#$%^&*(),.?":{}|<>]/.test(novaSenha) ? styles.valido : ''}>
                  Um caractere especial (!@#$%...)
                </li>
              </ul>
            </div>

            {erro && (
              <div className={styles.erro}>
                <FiAlertCircle />
                <span>{erro}</span>
              </div>
            )}

            <button
              type="submit"
              className={styles.submitButton}
              disabled={loading || !token}
            >
              {loading ? 'Redefinindo...' : 'Redefinir Senha'}
            </button>
          </form>

          <div className={styles.footer}>
            <Link href="/perfil">Voltar para Minha Conta</Link>
          </div>
        </div>
      </div>
    </div>
  );
}

export default function NovaSenhaPage() {
  return (
    <Suspense fallback={<div>Carregando...</div>}>
      <NovaSenhaContent />
    </Suspense>
  );
}

/* eslint-disable @typescript-eslint/no-explicit-any */
'use client';

import { useState, useEffect } from 'react';
import { useRouter, useParams } from 'next/navigation';
import Link from 'next/link';
import { useAuth } from '@/contexts/AuthContext';
import { useToast } from '@/contexts/ToastContext';
import Breadcrumbs from '@/components/Breadcrumbs/Breadcrumbs';
import { orderService, returnService } from '@/services/api';
import { Devolucao } from '@/types';
import { FiPackage, FiTruck, FiCheck, FiMapPin, FiCreditCard, FiCopy, FiX, FiRefreshCcw } from 'react-icons/fi';
import { toNumber, formatPrice } from '@/utils/formatPrice';
import styles from './pedido-detalhes.module.scss';

interface Pedido {
  id: number;
  usuario_id: number;
  status: string;
  subtotal: number;
  frete: number;
  desconto: number;
  total: number;
  forma_pagamento: string;
  entrega_tipo?: string;
  retirada_prazo_vencimento?: string | null;
  retirada_confirmada_em?: string | null;
  retirada_confirmado_por_nome?: string | null;
  retirada_observacao?: string | null;
  pagamento_na_retirada?: boolean;
  retirada_codigo?: string | null;
  codigo_rastreio?: string;
  data_pedido: string;
  data_atualizacao: string;
  itens: any[];
  cep?: string;
  rua?: string;
  numero?: string;
  complemento?: string;
  bairro?: string;
  cidade?: string;
  estado?: string;
  asaas_invoice_url?: string | null;
  asaas_boleto_url?: string | null;
  asaas_pix_qr_code?: string | null;
  asaas_pix_payload?: string | null;
  asaas_payment_status?: string | null;
  asaas_billing_type?: string | null;
}

const isPedidoRetiradaLocal = (pedido: Pedido) => {
  const entregaTipo = String(pedido.entrega_tipo || '').toLowerCase().trim();
  const status = String(pedido.status || '').toLowerCase().trim();

  return (
    ['retirada_local', 'retirada no local', 'retirada-no-local', 'retirada', 'retirar_no_local'].includes(entregaTipo) ||
    ['pronto_para_retirada', 'aguardando_pagamento_retirada', 'pendente_pagamento_retirada', 'retirado'].includes(status) ||
    Boolean(pedido.retirada_codigo)
  );
};

export default function PedidoDetalhesPage() {
  const params = useParams();
  const idParam = params?.id;
  const id = Array.isArray(idParam) ? idParam[0] : idParam;
  const router = useRouter();
  const { user } = useAuth();
  const toast = useToast();
  const [pedido, setPedido] = useState<Pedido | null>(null);
  const [loading, setLoading] = useState(true);
  const [devolucoes, setDevolucoes] = useState<Devolucao[]>([]);
  const [loadingDevolucoes, setLoadingDevolucoes] = useState(false);
  const [submittingDevolucao, setSubmittingDevolucao] = useState(false);
  const [formData, setFormData] = useState({
    tipo: 'troca',
    motivo: '',
    justificativa: '',
    observacoes: '',
  });
  const [selectedItems, setSelectedItems] = useState<Record<number, { quantidade: number; motivo_item: string }>>({});
  const [anexos, setAnexos] = useState<FileList | null>(null);

  useEffect(() => {
    if (!user) {
      toast.warning('Faça login para ver seus pedidos');
      router.push('/perfil');
      return;
    }
    if (!id) {
      return;
    }
    carregarPedido();
  }, [id, user]);

  const carregarPedido = async () => {
    setLoading(true);
    try {
      if (!id) return;
      const response = await orderService.getById(parseInt(id));
      if (response.success && response.data) {
        setPedido(response.data);
        carregarDevolucoes(response.data.id);
      }
    } catch (error: any) {
      toast.error(error.message || 'Erro ao carregar pedido');
      router.push('/pedidos');
    } finally {
      setLoading(false);
    }
  };

  const carregarDevolucoes = async (pedidoId: number) => {
    setLoadingDevolucoes(true);
    try {
      const response = await returnService.getAll({ pedido_id: pedidoId });
      if (response.success) {
        setDevolucoes(response.data || []);
      }
    } catch (error) {
      console.error('Erro ao carregar devolucoes:', error);
    } finally {
      setLoadingDevolucoes(false);
    }
  };

  const handleToggleItem = (itemId: number, quantidadeMax: number) => {
    setSelectedItems((prev) => {
      if (prev[itemId]) {
        const updated = { ...prev };
        delete updated[itemId];
        return updated;
      }
      return {
        ...prev,
        [itemId]: {
          quantidade: Math.min(1, quantidadeMax),
          motivo_item: '',
        },
      };
    });
  };

  const handleQuantidadeChange = (itemId: number, value: string, quantidadeMax: number) => {
    const quantidade = Math.max(1, Math.min(quantidadeMax, Number.parseInt(value || '1', 10)));
    setSelectedItems((prev) => ({
      ...prev,
      [itemId]: {
        ...prev[itemId],
        quantidade,
      },
    }));
  };

  const handleMotivoItemChange = (itemId: number, value: string) => {
    setSelectedItems((prev) => ({
      ...prev,
      [itemId]: {
        ...prev[itemId],
        motivo_item: value,
      },
    }));
  };

  const resetForm = () => {
    setFormData({ tipo: 'troca', motivo: '', justificativa: '', observacoes: '' });
    setSelectedItems({});
    setAnexos(null);
  };

  const handleEnviarDevolucao = async (event: React.FormEvent) => {
    event.preventDefault();
    if (!pedido) return;

    const itensPayload = Object.entries(selectedItems).map(([itemId, item]) => ({
      pedido_item_id: Number.parseInt(itemId, 10),
      quantidade: item.quantidade,
      motivo_item: item.motivo_item,
    }));

    if (itensPayload.length === 0) {
      toast.warning('Selecione pelo menos um item');
      return;
    }

    setSubmittingDevolucao(true);
    try {
      if (anexos && anexos.length > 0) {
        const form = new FormData();
        form.append('pedido_id', String(pedido.id));
        form.append('tipo', formData.tipo);
        form.append('motivo', formData.motivo);
        form.append('justificativa', formData.justificativa);
        if (formData.observacoes) {
          form.append('observacoes', formData.observacoes);
        }
        form.append('itens', JSON.stringify(itensPayload));
        Array.from(anexos).forEach((file) => form.append('anexos', file));
        await returnService.create(form);
      } else {
        await returnService.create({
          pedido_id: pedido.id,
          tipo: formData.tipo,
          motivo: formData.motivo,
          justificativa: formData.justificativa,
          observacoes: formData.observacoes || undefined,
          itens: itensPayload,
        });
      }

      toast.success('Solicitacao enviada com sucesso');
      resetForm();
      carregarDevolucoes(pedido.id);
    } catch (error: any) {
      toast.error(error.message || 'Erro ao enviar solicitacao');
    } finally {
      setSubmittingDevolucao(false);
    }
  };

  const handleRecorrer = async (devolucaoId: number) => {
    const justificativa = prompt('Informe a justificativa para recorrer (minimo 10 caracteres):');
    if (!justificativa || justificativa.trim().length < 10) {
      toast.warning('Justificativa invalida');
      return;
    }

    try {
      await returnService.appeal(devolucaoId, justificativa.trim());
      toast.success('Recorrencia enviada');
      if (pedido) {
        carregarDevolucoes(pedido.id);
      }
    } catch (error: any) {
      toast.error(error.message || 'Erro ao recorrer');
    }
  };

  const copiarRastreio = () => {
    if (pedido?.codigo_rastreio) {
      navigator.clipboard.writeText(pedido.codigo_rastreio);
      toast.success('Código de rastreio copiado!');
    }
  };

  const copiarPix = () => {
    if (pedido?.asaas_pix_payload) {
      navigator.clipboard.writeText(pedido.asaas_pix_payload);
      toast.success('Código PIX copiado!');
    }
  };

  const getPixImageSrc = (value?: string | null) => {
    if (!value) return null;
    if (value.startsWith('data:image')) return value;
    if (/^[A-Za-z0-9+/=]+$/.test(value)) {
      return `data:image/png;base64,${value}`;
    }
    return value;
  };

  const handleCancelarPedido = async () => {
    if (!pedido) return;

    if (!confirm('Tem certeza que deseja cancelar este pedido?')) {
      return;
    }

    try {
      await orderService.cancel(pedido.id);
      toast.success('Pedido cancelado com sucesso');
      carregarPedido();
    } catch (error: any) {
      toast.error(error.message || 'Erro ao cancelar pedido');
    }
  };

  const getStatusColor = (status: string) => {
    const colorMap: { [key: string]: string } = {
      pendente: '#FFA726',
      pendente_pagamento_retirada: '#FFA726',
      aguardando_pagamento_retirada: '#FFA726',
      pronto_para_retirada: '#7E57C2',
      retirado: '#66BB6A',
      pago: '#42A5F5',
      processando: '#AB47BC',
      enviado: '#29B6F6',
      devolucao: '#FFB74D',
      devolvido: '#66BB6A',
      entregue: '#66BB6A',
      cancelado: '#EF5350',
    };
    return colorMap[status] || '#999';
  };

  const getStatusText = (status: string) => {
    const statusMap: Record<string, string> = {
      pendente: 'Pendente',
      pendente_pagamento_retirada: 'Aguardando pagamento',
      aguardando_pagamento_retirada: 'Aguardando pagamento',
      pronto_para_retirada: 'Pronto para retirada',
      retirado: 'Retirado',
      pago: 'Pago',
      processando: 'Processando',
      enviado: 'Enviado',
      devolucao: 'Devolucao',
      devolvido: 'Devolvido',
      entregue: 'Entregue',
      cancelado: 'Cancelado',
    };
    return statusMap[status] || status;
  };

  const formatarData = (data: string) => {
    const date = new Date(data);
    return date.toLocaleDateString('pt-BR', {
      day: '2-digit',
      month: 'long',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    });
  };

  const getFormaPagamento = (forma: string) => {
    const formasMap: Record<string, string> = {
      pix: 'PIX',
      cartao: 'Cartão de Crédito',
      boleto: 'Boleto Bancário',
      local: 'Pagamento na retirada',
    };
    return formasMap[forma] || forma;
  };

  const formatarValor = (valor?: number | string | null) => {
    return formatPrice(toNumber(valor || 0));
  };

  if (loading || !pedido) {
    return (
      <div className={styles.loading}>
        <p>Carregando pedido...</p>
      </div>
    );
  }

  const enderecoDisponivel = Boolean(pedido.rua || pedido.cep);
  const isRetiradaLocal = isPedidoRetiradaLocal(pedido);
  const shouldShowPayment = ['pix', 'boleto', 'cartao'].includes(pedido.forma_pagamento);
  const pixQr = shouldShowPayment ? getPixImageSrc(pedido.asaas_pix_qr_code) : null;
  const boletoUrl = shouldShowPayment ? (pedido.asaas_boleto_url || pedido.asaas_invoice_url) : null;
  const cartaoUrl = shouldShowPayment ? pedido.asaas_invoice_url : null;

  const podeCandelar = ['pendente', 'processando', 'pago', 'pronto_para_retirada', 'pendente_pagamento_retirada', 'aguardando_pagamento_retirada'].includes(pedido.status);
  const podeSolicitar = ['devolucao', 'entregue'].includes(pedido.status);
  const statusEnviado = ['enviado', 'devolucao', 'devolvido', 'entregue'].includes(pedido.status);
  const statusEntregue = ['devolucao', 'devolvido', 'entregue'].includes(pedido.status);
  const etapaFinalTitulo = pedido.status === 'devolvido'
    ? 'Pedido Devolvido'
    : pedido.status === 'devolucao'
    ? 'Pedido em Devolucao'
    : 'Pedido Entregue';
  const etapaFinalMensagem = pedido.status === 'devolvido'
    ? 'Devolucao concluida'
    : pedido.status === 'devolucao'
    ? 'Devolucao em andamento'
    : 'Pedido entregue com sucesso';

  return (
    <div className={styles.page}>
      <Breadcrumbs
        items={[
          { label: 'Meus Pedidos', href: '/pedidos' },
          { label: `Pedido #${pedido.id}` },
        ]}
      />

      <div className={styles.container}>
        {/* Header */}
        <div className={styles.header}>
          <div>
            <h1>Pedido #{pedido.id}</h1>
            {isRetiradaLocal && (
              <p>
                Código de retirada: {pedido.retirada_codigo || 'disponível após confirmação do pagamento'}
              </p>
            )}
            <p>Realizado em {formatarData(pedido.data_pedido)}</p>
          </div>
          <div
            className={styles.statusBadge}
            style={{ background: getStatusColor(pedido.status) }}
          >
            {getStatusText(pedido.status)}
          </div>
        </div>

        <div className={styles.content}>
          {/* Status do Pedido */}
          <div className={styles.trackingCard}>
            <h2>Status do Pedido</h2>
            <div className={styles.timeline}>
              {/* Etapa 1: Pedido Confirmado */}
              <div className={`${styles.timelineItem} ${styles.completed}`}>
                <div className={styles.timelineIcon}>
                  <FiCheck />
                </div>
                <div className={styles.timelineContent}>
                  <h4>Pedido Confirmado</h4>
                  <p>{formatarData(pedido.data_pedido)}</p>
                </div>
              </div>

              {/* Etapa 2: Pedido em Preparação */}
              <div className={`${styles.timelineItem} ${pedido.status !== 'pendente' ? styles.completed : ''}`}>
                <div className={styles.timelineIcon}>
                  <FiPackage />
                </div>
                <div className={styles.timelineContent}>
                  <h4>Pedido em Preparação</h4>
                  {pedido.status !== 'pendente' && <p>Preparando seu pedido</p>}
                </div>
              </div>

              {isRetiradaLocal ? (
                <>
                  {/* Etapa 3 (Retirada): Pedido Preparado */}
                  <div className={`${styles.timelineItem} ${['pronto_para_retirada', 'retirado'].includes(pedido.status) ? styles.completed : ''}`}>
                    <div className={styles.timelineIcon}>
                      <FiCheck />
                    </div>
                    <div className={styles.timelineContent}>
                      <h4>Pedido Preparado</h4>
                      {['pronto_para_retirada', 'retirado'].includes(pedido.status) && (
                        <p>Seu pedido está pronto para retirada</p>
                      )}
                    </div>
                  </div>

                  {/* Etapa 4 (Retirada): Pedido Retirado */}
                  <div className={`${styles.timelineItem} ${pedido.status === 'retirado' ? styles.completed : ''}`}>
                    <div className={styles.timelineIcon}>
                      <FiCheck />
                    </div>
                    <div className={styles.timelineContent}>
                      <h4>Pedido Retirado</h4>
                      {pedido.status === 'retirado' && (
                        <>
                          <p>Retirado por: {pedido.retirada_confirmado_por_nome}</p>
                          <p>{formatarData(pedido.retirada_confirmada_em || '')}</p>
                        </>
                      )}
                    </div>
                  </div>
                </>
              ) : (
                <>
                  {/* Etapa 3 (Entrega): Pedido Enviado */}
                  <div className={`${styles.timelineItem} ${statusEnviado ? styles.completed : ''}`}>
                    <div className={styles.timelineIcon}>
                      <FiTruck />
                    </div>
                    <div className={styles.timelineContent}>
                      <h4>Pedido Enviado</h4>
                      {statusEnviado && (
                        <p>{formatarData(pedido.data_atualizacao)}</p>
                      )}
                    </div>
                  </div>

                  {/* Etapa 4 (Entrega): Pedido Entregue */}
                  <div className={`${styles.timelineItem} ${statusEntregue ? styles.completed : ''}`}>
                    <div className={styles.timelineIcon}>
                      <FiCheck />
                    </div>
                    <div className={styles.timelineContent}>
                      <h4>{etapaFinalTitulo}</h4>
                      {statusEntregue && <p>{etapaFinalMensagem}</p>}
                    </div>
                  </div>
                </>
              )}
            </div>

            {pedido.codigo_rastreio && (
              <div className={styles.trackingInfo}>
                <div className={styles.trackingCode}>
                  <FiMapPin />
                  <div>
                    <strong>Código de Rastreio</strong>
                    <p>{pedido.codigo_rastreio}</p>
                  </div>
                </div>
                <button className={styles.copyButton} onClick={copiarRastreio}>
                  <FiCopy /> Copiar
                </button>
              </div>
            )}
          </div>

          {/* Itens do Pedido */}
          <div className={styles.itemsCard}>
            <h2>Itens do Pedido</h2>
            <div className={styles.itemsList}>
              {pedido.itens && pedido.itens.map((item: any) => {
                const itemImage = Array.isArray(item.produto_imagens)
                  ? item.produto_imagens[0]
                  : item.produto_imagens;
                return (
                <div key={item.id} className={styles.item}>
                  <div className={styles.itemImage}>
                    {itemImage ? (
                      <img src={itemImage} alt={item.produto_nome} />
                    ) : (
                      <div className={styles.noImage}>Sem imagem</div>
                    )}
                  </div>
                  <div className={styles.itemInfo}>
                    <Link href={`/produtos/${item.produto_id}`}>
                      <h4>{item.produto_nome}</h4>
                    </Link>
                    {item.tamanho && <p>Tamanho: {item.tamanho}</p>}
                    {item.cor && (
                      <p>
                        Cor:{' '}
                        <span
                          className={styles.colorDot}
                          style={{ background: item.cor }}
                        />
                      </p>
                    )}
                    <p>Quantidade: {item.quantidade}</p>
                  </div>
                  <div className={styles.itemPrice}>
                    R$ {formatPrice(toNumber(item.preco_unitario) * item.quantidade)}
                  </div>
                </div>
              );
              })}
            </div>
          </div>

          {/* Endereço de Entrega */}
          {enderecoDisponivel && !isRetiradaLocal && (
            <div className={styles.addressCard}>
              <h2><FiMapPin /> Endereço de Entrega</h2>
              <div className={styles.address}>
                <p>{pedido.rua}, {pedido.numero}</p>
                {pedido.complemento && <p>{pedido.complemento}</p>}
                <p>{pedido.bairro}</p>
                <p>{pedido.cidade} - {pedido.estado}</p>
                <p>CEP: {pedido.cep}</p>
              </div>
            </div>
          )}

          {/* Retirada no Local */}
          {isRetiradaLocal && (
            <div className={styles.retiradaCard}>
              <h2><FiMapPin /> Retirada no Local</h2>

              {/* Código de Retirada em destaque */}
              {pedido.retirada_codigo && (
                <div className={styles.codigoRetirada}>
                  <p className={styles.labelCodigo}>Código de Retirada</p>
                  <div className={styles.codigoBox}>
                    <span className={styles.codigo}>{pedido.retirada_codigo}</span>
                    <button 
                      onClick={() => {
                        navigator.clipboard.writeText(pedido.retirada_codigo || '');
