            <div className={styles.summaryRow}>
              <span>Subtotal</span>
              <span>R$ {formatarValor(pedido.subtotal)}</span>
            </div>
            {pedido.desconto > 0 && (
              <div className={styles.summaryRow}>
                <span>Desconto</span>
                <span className={styles.discount}>
                  -R$ {formatarValor(pedido.desconto)}
