            <div className={styles.summaryRow}>
              <span>Frete</span>
              <span>{pedido.frete === 0 ? 'Grátis' : `R$ ${formatarValor(pedido.frete)}`}</span>
            </div>
            <div className={`${styles.summaryRow} ${styles.total}`}>
