'use client';

import { useState, useEffect, CSSProperties } from 'react';
import Link from 'next/link';
import { FiChevronLeft, FiChevronRight } from 'react-icons/fi';
import { bannerService } from '@/services/api';
import styles from './HeroSlider.module.scss';

interface Slide {
  id: number;
  title: string;
  subtitle: string;
  buttonText: string;
  buttonLink: string;
  image: string;
  backgroundColor: string;
}

interface HeroSliderProps {
  slides?: Slide[];
  autoPlay?: boolean;
  interval?: number;
}

export default function HeroSlider({ 
  slides: customSlides,
  autoPlay = true, 
  interval = 5000 
}: HeroSliderProps) {
  const [slides, setSlides] = useState<Slide[]>(customSlides || []);
  const [currentSlide, setCurrentSlide] = useState(0);
  const [isAnimating, setIsAnimating] = useState(false);
  const [loading, setLoading] = useState(!customSlides);

  // Buscar banners da API se não foram fornecidos
  useEffect(() => {
    if (!customSlides) {
      carregarBanners();
    }
  }, [customSlides]);

  const carregarBanners = async () => {
    try {
      setLoading(true);
      const response = await bannerService.getAll(true); // Apenas banners ativos

      if (response.success && response.data && response.data.length > 0) {
        // Converter formato do banco para formato do componente
        const bannersFormatados = response.data.map((banner: any) => ({
          id: banner.id,
          title: banner.titulo,
          subtitle: banner.subtitulo || '',
          buttonText: banner.texto_botao || 'Ver Mais',
          buttonLink: banner.link_botao || '/produtos',
          image: banner.imagem || '',
          backgroundColor: banner.cor_fundo || '#0C1C3A',
        }));

        setSlides(bannersFormatados);
      } else {
        setSlides([]);
      }
    } catch (error) {
      console.error('Erro ao carregar banners:', error);
      setSlides([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (!autoPlay || slides.length === 0) return;

    const timer = setInterval(() => {
      nextSlide();
    }, interval);

    return () => clearInterval(timer);
  }, [currentSlide, autoPlay, interval, slides.length]);

  const nextSlide = () => {
    if (isAnimating || slides.length === 0) return;
    setIsAnimating(true);
    setCurrentSlide((prev) => (prev + 1) % slides.length);
    setTimeout(() => setIsAnimating(false), 500);
  };

  const prevSlide = () => {
    if (isAnimating || slides.length === 0) return;
    setIsAnimating(true);
    setCurrentSlide((prev) => (prev - 1 + slides.length) % slides.length);
    setTimeout(() => setIsAnimating(false), 500);
  };

  const goToSlide = (index: number) => {
    if (isAnimating || index === currentSlide || slides.length === 0) return;
    setIsAnimating(true);
    setCurrentSlide(index);
    setTimeout(() => setIsAnimating(false), 500);
  };

  if (loading) {
    return (
      <div className={styles.heroSlider} style={{ minHeight: '400px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <div className="spinner-border" role="status">
          <span className="visually-hidden">Carregando...</span>
        </div>
      </div>
    );
  }

  if (slides.length === 0) {
    return null;
  }

  const normalizeHex = (value: string) => {
    if (!value) return '#0C1C3A';
    const hex = value.trim();
    if (/^#[0-9A-Fa-f]{6}$/.test(hex)) return hex;
    if (/^#[0-9A-Fa-f]{3}$/.test(hex)) {
      const r = hex[1];
      const g = hex[2];
      const b = hex[3];
      return `#${r}${r}${g}${g}${b}${b}`;
    }
    return '#0C1C3A';
  };

  const hexToRgb = (hex: string) => {
    const clean = normalizeHex(hex).slice(1);
    const r = parseInt(clean.slice(0, 2), 16);
    const g = parseInt(clean.slice(2, 4), 16);
    const b = parseInt(clean.slice(4, 6), 16);
    return { r, g, b };
  };

  const getLuminance = (hex: string) => {
    const { r, g, b } = hexToRgb(hex);
    const srgb = [r, g, b].map((c) => {
      const v = c / 255;
      return v <= 0.03928 ? v / 12.92 : Math.pow((v + 0.055) / 1.055, 2.4);
    });
    return 0.2126 * srgb[0] + 0.7152 * srgb[1] + 0.0722 * srgb[2];
  };

  const getBannerTheme = (bg: string) => {
    const background = normalizeHex(bg);
    const luminance = getLuminance(background);
    const isLight = luminance > 0.62;

    return {
      background,
      titleColor: isLight ? '#0B0F1A' : '#FFFFFF',
      subtitleColor: isLight ? 'rgba(11, 15, 26, 0.75)' : 'rgba(255, 255, 255, 0.85)',
      buttonBg: isLight ? '#0B0F1A' : '#FFFFFF',
      buttonText: isLight ? '#FFFFFF' : '#0B0F1A',
      buttonBorder: isLight ? 'rgba(11, 15, 26, 0.35)' : 'rgba(255, 255, 255, 0.5)',
      buttonHoverBg: isLight ? '#16223A' : '#E6ECF8',
      shadowColor: isLight ? 'rgba(0, 0, 0, 0.2)' : 'rgba(0, 0, 0, 0.45)',
    };
  };

  return (
    <div className={styles.heroSlider}>
      <div className={styles.slidesContainer}>
        {slides.map((slide, index) => (
          (() => {
            const theme = getBannerTheme(slide.backgroundColor);
            const slideStyle: CSSProperties = {
              backgroundColor: theme.background,
              ['--banner-title-color' as any]: theme.titleColor,
              ['--banner-subtitle-color' as any]: theme.subtitleColor,
              ['--banner-button-bg' as any]: theme.buttonBg,
              ['--banner-button-text' as any]: theme.buttonText,
              ['--banner-button-border' as any]: theme.buttonBorder,
              ['--banner-button-hover-bg' as any]: theme.buttonHoverBg,
              ['--banner-shadow-color' as any]: theme.shadowColor,
            };

            return (
          <div
            key={slide.id}
            className={`${styles.slide} ${index === currentSlide ? styles.active : ''}`}
            style={slideStyle}
          >
            <div className={styles.slideContent}>
              <div className={styles.textContent}>
                <h1 className={styles.title}>{slide.title}</h1>
                <p className={styles.subtitle}>{slide.subtitle}</p>
                <Link href={slide.buttonLink}>
                  <button className={styles.ctaButton}>{slide.buttonText}</button>
                </Link>
              </div>

              {slide.image && (
                <div className={styles.imageContent}>
                  <div 
                    className={styles.slideImage}
                    style={{ backgroundImage: `url(${slide.image})` }}
                  />
                </div>
              )}
            </div>
          </div>
            );
          })()
        ))}
      </div>

      {/* Controles */}
      {slides.length > 1 && (
        <>
          <button 
            className={`${styles.navButton} ${styles.prev}`}
            onClick={prevSlide}
            aria-label="Slide anterior"
          >
            <FiChevronLeft />
          </button>

          <button 
            className={`${styles.navButton} ${styles.next}`}
            onClick={nextSlide}
            aria-label="Próximo slide"
          >
            <FiChevronRight />
          </button>

          {/* Indicadores */}
          <div className={styles.indicators}>
            {slides.map((_, index) => (
              <button
                key={index}
                className={`${styles.indicator} ${index === currentSlide ? styles.active : ''}`}
                onClick={() => goToSlide(index)}
                aria-label={`Ir para slide ${index + 1}`}
              />
            ))}
          </div>
        </>
      )}
    </div>
  );
}

'use client';

import { useState, useRef } from 'react';
import { FiUpload, FiX } from 'react-icons/fi';
import styles from './ImageUpload.module.scss';

interface ImageUploadProps {
  onImageSelected: (file: File) => void;
  onImageRemoved?: () => void;
  previewUrl?: string;
  accept?: string;
  maxSize?: number; // em MB
  label?: string;
}

export default function ImageUpload({
  onImageSelected,
  onImageRemoved,
  previewUrl,
  accept = 'image/*',
  maxSize = 5,
  label = 'Upload de Imagem',
}: ImageUploadProps) {
  const [isDragging, setIsDragging] = useState(false);
  const [error, setError] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const validateFile = (file: File): boolean => {
    setError('');

    // Validar tipo
    if (!file.type.startsWith('image/')) {
      setError('Por favor, selecione um arquivo de imagem válido');
      return false;
    }

    // Validar tamanho
    const fileSizeMB = file.size / (1024 * 1024);
    if (fileSizeMB > maxSize) {
      setError(`O arquivo não pode exceder ${maxSize}MB`);
      return false;
    }

    return true;
  };

  const handleFileSelect = (file: File) => {
    if (validateFile(file)) {
      onImageSelected(file);
    }
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      handleFileSelect(e.target.files[0]);
    }
  };

  const handleDragOver = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);

    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      handleFileSelect(e.dataTransfer.files[0]);
    }
  };

  const handleRemoveImage = () => {
    setError('');
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
    onImageRemoved?.();
  };

  return (
    <div className={styles.container}>
      <label className={styles.label}>{label}</label>

      {previewUrl ? (
        <div className={styles.preview}>
          <img src={previewUrl} alt="Preview" className={styles.previewImage} />
          <button
            type="button"
            onClick={handleRemoveImage}
            className={styles.removeButton}
            title="Remover imagem"
          >
            <FiX />
          </button>
        </div>
      ) : (
        <div
          className={`${styles.dropZone} ${isDragging ? styles.dragging : ''}`}
          onDragOver={handleDragOver}
          onDragLeave={handleDragLeave}
          onDrop={handleDrop}
          onClick={() => fileInputRef.current?.click()}
        >
          <FiUpload size={32} />
          <p>Arraste uma imagem ou clique para selecionar</p>
          <small>Máximo {maxSize}MB • Formatos: JPG, PNG, WebP</small>
          <input
            ref={fileInputRef}
            type="file"
            accept={accept}
            onChange={handleInputChange}
            className={styles.hiddenInput}
          />
        </div>
      )}

      {error && <div className={styles.error}>{error}</div>}
    </div>
  );
}

