'use client';

import { useEffect, useState } from 'react';
import Breadcrumbs from '@/components/Breadcrumbs/Breadcrumbs';
import { institutionalContentService } from '@/services/api';
import styles from './InstitutionalContentPage.module.scss';

interface InstitutionalContentPageProps {
  slug: string;
  breadcrumbLabel: string;
  defaultTitle: string;
}

interface ConteudoInstitucional {
  slug: string;
  titulo: string;
  resumo?: string;
  conteudo_html?: string;
}

const normalizeUtf8 = (value?: string): string => {
  if (!value) return '';

  const hasPossibleMojibake = /Ã.|Â.|â.|├|�/.test(value);
  if (!hasPossibleMojibake) {
    return value;
  }

  try {
    const bytes = Uint8Array.from(value, (char) => char.charCodeAt(0));
    const decoded = new TextDecoder('utf-8').decode(bytes);
    return decoded || value;
  } catch {
    return value;
  }
};

export default function InstitutionalContentPage({
  slug,
  breadcrumbLabel,
  defaultTitle,
}: InstitutionalContentPageProps) {
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [conteudo, setConteudo] = useState<ConteudoInstitucional | null>(null);

  const carregarConteudo = async () => {
    try {
      setLoading(true);
      setError('');
      const response = await institutionalContentService.getBySlug(slug);

      if (!response.success || !response.data) {
        setConteudo(null);
        setError('Conteúdo indisponível no momento.');
        return;
      }

      setConteudo({
        ...response.data,
        titulo: normalizeUtf8(response.data.titulo),
        resumo: normalizeUtf8(response.data.resumo || ''),
        conteudo_html: normalizeUtf8(response.data.conteudo_html || ''),
      });
    } catch (err: any) {
      setConteudo(null);
      setError(err?.message || 'Não foi possível carregar o conteúdo.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    carregarConteudo();
  }, [slug]);

  return (
    <div className={styles.page}>
      <div className="container">
        <Breadcrumbs items={[{ label: breadcrumbLabel }]} />

        <div className={styles.hero}>
          <h1>{conteudo?.titulo || defaultTitle}</h1>
          {conteudo?.resumo ? <p>{conteudo.resumo}</p> : null}
        </div>

        {loading ? (
          <div className={styles.loading}>Carregando conteúdo...</div>
        ) : error ? (
          <div className={styles.error}>
            <p>{error}</p>
            <button type="button" className={styles.retryButton} onClick={carregarConteudo}>
              Tentar novamente
            </button>
          </div>
        ) : conteudo?.conteudo_html ? (
          <article
            className={styles.content}
            dangerouslySetInnerHTML={{ __html: conteudo.conteudo_html }}
          />
        ) : (
          <div className={styles.empty}>Conteúdo ainda não publicado.</div>
        )}
      </div>
    </div>
  );
}

'use client';

import { useEffect, useRef, useState } from 'react';
import { FiBell, FiCheck, FiTrash2 } from 'react-icons/fi';
import { io, Socket } from 'socket.io-client';
import { notificationService } from '@/services/api';
import { useAuth } from '@/contexts/AuthContext';
import { useNotification } from '@/hooks/useNotification';
import { Notificacao } from '@/types';
import styles from './NotificationsBell.module.scss';

const getSocketUrl = () => {
  const apiUrl = process.env.NEXT_PUBLIC_API_URL || '';
  if (apiUrl.endsWith('/api')) {
    return apiUrl.slice(0, -4);
  }
  if (apiUrl) {
    return apiUrl;
  }
  if (typeof window !== 'undefined') {
    return window.location.origin;
  }
  return 'http://localhost:5000';
};

export default function NotificationsBell() {
  const { user } = useAuth();
  const { info } = useNotification();
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [items, setItems] = useState<Notificacao[]>([]);
  const [unreadCount, setUnreadCount] = useState(0);
  const panelRef = useRef<HTMLDivElement | null>(null);
  const socketRef = useRef<Socket | null>(null);
  const hasUnread = unreadCount > 0;

  const fetchUnreadCount = async () => {
    try {
      const response = await notificationService.unread();
      if (response?.success) {
        setUnreadCount(Number(response.nao_lidas || 0));
      }
    } catch (error) {
      console.error('Erro ao buscar nao lidas:', error);
    }
  };

  const fetchNotifications = async () => {
    try {
      setLoading(true);
      const response = await notificationService.list({ pagina: 1, limite: 20 });
      if (response?.success) {
        setItems(response.data || []);
        if (typeof response.nao_lidas !== 'undefined') {
          setUnreadCount(Number(response.nao_lidas || 0));
        }
      }
    } catch (error) {
      console.error('Erro ao buscar notificacoes:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleToggle = () => {
    const next = !open;
    setOpen(next);
    if (next) {
      fetchNotifications();
    }
  };

  const handleMarkRead = async (id: number) => {
    try {
      await notificationService.markRead(id);
      setItems((prev) =>
        prev.map((item) =>
          item.id === id ? { ...item, lida_em: item.lida_em || new Date().toISOString() } : item
        )
      );
      setUnreadCount((prev) => Math.max(prev - 1, 0));
    } catch (error) {
      console.error('Erro ao marcar lida:', error);
    }
  };

  const handleMarkAllRead = async () => {
    try {
      await notificationService.markAllRead();
      const now = new Date().toISOString();
      setItems((prev) => prev.map((item) => ({ ...item, lida_em: item.lida_em || now })));
      setUnreadCount(0);
    } catch (error) {
      console.error('Erro ao marcar todas como lidas:', error);
    }
  };

  const handleRemove = async (id: number) => {
    try {
      const item = items.find((current) => current.id === id);
      await notificationService.remove(id);
      setItems((prev) => prev.filter((current) => current.id !== id));
      if (item && !item.lida_em) {
        setUnreadCount((prev) => Math.max(prev - 1, 0));
      }
    } catch (error) {
      console.error('Erro ao remover notificacao:', error);
    }
  };

  useEffect(() => {
    if (!user) {
      setItems([]);
      setUnreadCount(0);
      if (socketRef.current) {
        socketRef.current.disconnect();
        socketRef.current = null;
      }
      return;
    }

    fetchUnreadCount();

    if (socketRef.current) {
      return;
    }

    const token = typeof window !== 'undefined' ? localStorage.getItem('token') : null;
    if (!token) {
      return;
    }

    const socket = io(getSocketUrl(), {
      auth: { token },
    });

    socket.on('notification:new', (notification: Notificacao) => {
      setItems((prev) => {
        if (prev.some((item) => item.id === notification.id)) {
          return prev;
        }
        return [notification, ...prev].slice(0, 50);
      });
      if (!notification.lida_em) {
        setUnreadCount((prev) => prev + 1);
      }
      info(notification.titulo, notification.mensagem);
    });

    socketRef.current = socket;

    return () => {
      socket.disconnect();
      socketRef.current = null;
    };
  }, [user]);

  useEffect(() => {
    if (!open) return;
    const handleClickOutside = (event: MouseEvent) => {
      if (panelRef.current && !panelRef.current.contains(event.target as Node)) {
        setOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [open]);

  if (!user) {
    return null;
  }

  return (
    <div className={styles.wrapper} ref={panelRef}>
      <button
        className={`${styles.bellButton} ${hasUnread ? styles.bellActive : ''}`}
        onClick={handleToggle}
        title="Notificacoes"
      >
        <FiBell size={20} />
        {unreadCount > 0 && <span className={styles.badge}>{unreadCount}</span>}
      </button>

      {open && (
        <div className={styles.panel}>
          <div className={styles.panelHeader}>
            <span>Notificacoes</span>
            <button className={styles.markAllButton} onClick={handleMarkAllRead}>
              Marcar todas
            </button>
          </div>

          <div className={styles.panelBody}>
            {loading && <p className={styles.empty}>Carregando...</p>}
            {!loading && items.length === 0 && (
              <p className={styles.empty}>Sem notificacoes.</p>
            )}
            {!loading && items.length > 0 && (
              <ul className={styles.list}>
                {items.map((item) => (
                  <li
                    key={item.id}
                    className={`${styles.item} ${item.lida_em ? styles.read : styles.unread}`}
                  >
                    <div className={styles.itemRow}>
                      <div className={styles.itemText}>
                        <span className={styles.title}>{item.titulo}</span>
                        <span className={styles.dot} aria-hidden="true">•</span>
                        <span className={styles.message}>{item.mensagem}</span>
                      </div>
                      <div className={styles.itemMeta}>
                        <span className={styles.time}>
                          {new Date(item.criada_em).toLocaleString('pt-BR')}
                        </span>
                        <button
                          className={styles.actionButton}
                          onClick={() => handleMarkRead(item.id)}
                          disabled={Boolean(item.lida_em)}
                          title="Marcar como lida"
                        >
                          <FiCheck size={14} />
                        </button>
                        <button
                          className={styles.actionButton}
                          onClick={() => handleRemove(item.id)}
                          title="Excluir"
                        >
                          <FiTrash2 size={14} />
                        </button>
                      </div>
                    </div>
                  </li>
                ))}
              </ul>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

/* eslint-disable react/no-unescaped-entities */
'use client';

import { useState, useEffect, useRef } from 'react';
import { useRouter } from 'next/navigation';
import { FiSearch, FiX } from 'react-icons/fi';
import { Product } from '@/types';
import { productService } from '@/services/api';
import { formatPrice } from '@/utils/formatPrice';
import styles from './SearchBar.module.scss';

interface SearchBarProps {
  placeholder?: string;
  autoFocus?: boolean;
  limit?: number;
  orderBy?: 'data_criacao' | 'preco' | 'nome' | 'vendas';
  direction?: 'ASC' | 'DESC';
}

export default function SearchBar({
  placeholder = 'Buscar produtos...',
  autoFocus = false,
  limit = 6,
  orderBy = 'nome',
  direction = 'ASC',
}: SearchBarProps) {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<Product[]>([]);
  const [isOpen, setIsOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const searchRef = useRef<HTMLDivElement>(null);
  const router = useRouter();

  // Fechar dropdown ao clicar fora
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (searchRef.current && !searchRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Buscar produtos com debounce
  useEffect(() => {
    if (query.length < 2) {
      setResults([]);
      setIsOpen(false);
      return;
    }

    setLoading(true);
    const timeoutId = setTimeout(async () => {
      try {
        const response = await productService.search(query, {
          limite: limit,
          ordem: orderBy,
          direcao: direction,
        });
        if (response.success && response.data) {
          setResults(response.data.slice(0, limit));
          setIsOpen(true);
        }
      } catch (error) {
        console.error('Erro ao buscar produtos:', error);
        setResults([]);
        setIsOpen(false);
      } finally {
        setLoading(false);
      }
    }, 300);

    return () => clearTimeout(timeoutId);
  }, [query, limit, orderBy, direction]);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    if (query.trim()) {
      router.push(`/produtos?q=${encodeURIComponent(query)}`);
      setIsOpen(false);
      setQuery('');
    }
  };

  const handleSelectProduct = (productId: number) => {
    router.push(`/produtos/${productId}`);
    setIsOpen(false);
    setQuery('');
  };

  const clearSearch = () => {
    setQuery('');
    setResults([]);
    setIsOpen(false);
  };

  return (
    <div className={styles.searchBar} ref={searchRef}>
      <form onSubmit={handleSearch} className={styles.searchForm}>
        <FiSearch className={styles.searchIcon} />
        <input
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          onFocus={() => query.length >= 2 && setIsOpen(true)}
          placeholder={placeholder}
          className={styles.searchInput}
          autoFocus={autoFocus}
        />
        {query && (
          <button
            type="button"
            onClick={clearSearch}
            className={styles.clearButton}
            aria-label="Limpar busca"
          >
            <FiX />
          </button>
        )}
      </form>

      {/* Dropdown de resultados */}
      {isOpen && (
        <div className={styles.dropdown}>
          {loading ? (
            <div className={styles.loading}>Buscando...</div>
          ) : results.length > 0 ? (
            <>
              <div className={styles.results}>
                {results.map((product) => (
                  <div
                    key={product.id}
                    className={styles.resultItem}
                    onClick={() => handleSelectProduct(product.id)}
                  >
                    <div className={styles.resultImage}>
                      {product.imagens[0] ? (
                        <img src={product.imagens[0]} alt={product.nome} />
                      ) : (
                        <div className={styles.noImage}>Sem imagem</div>
                      )}
                    </div>
                    <div className={styles.resultInfo}>
                      <h4>{product.nome}</h4>
                      <div className={styles.resultPrice}>
                        {product.preco_original && (
                          <span className={styles.oldPrice}>
                            R$ {formatPrice(product.preco_original)}
                          </span>
                        )}
                        <span className={styles.price}>
                          R$ {formatPrice(product.preco)}
                        </span>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
              <button
                type="button"
                onClick={handleSearch}
                className={styles.seeAllButton}
              >
                Ver todos os resultados para "{query}"
              </button>
            </>
          ) : (
            <div className={styles.noResults}>
              Nenhum produto encontrado para "{query}"
            </div>
          )}
        </div>
      )}
    </div>
  );
}

